import { NavigationEvent } from '../../../events/navigation/NavigationEvent.event';
import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { Button, ButtonProps } from '../form/button/Button';
import { NavigationOptions, Router } from '../../../routing/Router';

export interface LinkButtonProps extends ButtonProps {
  disableOnOwnPath?: boolean;
  navigationOptions?: NavigationOptions;
}

export class LinkButton extends Button {
  private _path: string;
  private _cleanupEventListener?: () => void;
  private _disableOnOwnPath: boolean;
  constructor(children: HTMDNode, path: string, props?: LinkButtonProps) {
    super(children, {
      ...props,
      onClickHandler: (e) => {
        Router.navigateTo(path, props?.navigationOptions);
        props?.onClickHandler?.(e);
      },
    });
    this._path = path;
    this._disableOnOwnPath = props?.disableOnOwnPath ?? true;
  }

  private _onNavigationHandler() {
    if (!this._disableOnOwnPath) return;

    this._cleanupEventListener?.();
    this._cleanupEventListener = NavigationEvent.listener((e) => {
      this.isDisabled = e?.to === this._path;
    });
  }

  remove() {
    this._cleanupEventListener?.();
    this._cleanupEventListener = undefined;
    super.remove();
  }
  protected _applyEventListeners(): void {
    super._applyEventListeners();
    this._onNavigationHandler();
  }

  get path() {
    return this._path;
  }
}
