import { Route } from './Route';
import { HTMDNode } from '../types/DOM/HTMDNode.type';

export interface RouteConfig {
  setRouteTitle: (title: string) => void;
  // setOnRefreshHandler: (callback: () => void) => void;
  // eslint-disable-next-line @typescript-eslint/naming-convention
  $DANGEROUS__route_backdoor: Route;
}

export async function defineRoute(
  closureCallback: (config: RouteConfig) => Promise<HTMDNode> | HTMDNode
) {
  const route = new Route();

  const config: RouteConfig = {
    setRouteTitle: (title) => {
      route.title = title;
    },
    // eslint-disable-next-line @typescript-eslint/naming-convention
    $DANGEROUS__route_backdoor: route,
  };
  const refreshHandler = async () => {
    route.children = await closureCallback(config);
  };

  route.onRefreshHandler = async () => await refreshHandler();

  return route;
}
