import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { HTMDElement, HTMDElementProps } from '../../abstracts/HTMDElement.abstract';

export interface TextProps extends HTMDElementProps {
  type?: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'label' | 'p' | 'span';
  for?: string;
  title?: string;
}

export class Text extends HTMDElement {
  public type: TextProps['type'];
  public for: string;
  public title: string;
  constructor(children?: HTMDNode, props?: TextProps) {
    super(children, props);
    this.type = props?.type || 'p';
    this.for = this.type === 'label' ? (props?.for ?? '') : '';
    this.title = props?.title ?? '';
  }

  toString(): string {
    return `<${this.type} 
              id="${this.id}"
              class="${this.class}" 
              ${this.type === 'label' ? `for="${this.for}"` : ''}
              ${this.title ? `title="${this.title}"` : ''}
              />`;
  }
}
