import { each } from 'lodash';
import { SPARC_PREFIX } from '../../utils/misc/identity';
import { resolvePath } from '../../utils/misc/path';

export type pageResetOptions = {
  /**
   * Boolean flag that indicates if the console should be cleared once this function executes,
   */
  clearConsole: boolean;
  /**
   * Boolean flag that indicates if the script should remove all style and link tags that load css
   */
  removeStyles: boolean;
  /**
   * Optional path to a client/app theme CSS file.
   * Loaded AFTER the base SPARC theme, overriding tokens and adding custom styles.
   */
  themePath?: string;
};
/**
 * A function that hides all the sharepoint UI and prepends a div#page element to act as a wrapper.
 * Once this function is called, another one becomes globally available to show the UI.
 * @param {pageResetOptions} options refer to the pageResetOptions type for more docs
 *
 * @see displaySharePointUI - to show SP's ui back again.
 */
export function pageReset(
  { clearConsole = true, removeStyles = true, themePath }: pageResetOptions = {

    clearConsole: true,
    removeStyles: true,
  }
) {
  if (clearConsole) window.console.clear();

  const resetClass = `${SPARC_PREFIX}-reset`;

  if (removeStyles) {
    const inheritedStyles: HTMLElement[] = [],
      s1 = $(`link[rel="stylesheet"]`),
      s2 = $(`style`);

    inheritedStyles.push(...s1.toArray());
    inheritedStyles.push(...s2.toArray());
    s1.remove();
    s2.remove();

    // revert changes
    window.displaySharePointUI = () => {
      each(inheritedStyles, (tag) => $('head').append(tag));
      $('body').removeClass(resetClass);
    };
  }

  $('body').prepend("<div id='root'/>");
  $('body').addClass(resetClass);
  // feeling lucky today...who needs css files?? :P
  //lol this is actually useful in order to ensure that these styles are always applied regardless of sparc.css or theme
  //leaving this 2 last comments here just so i don't feel so dumb in the future
  const styleTag = `
    <style>
      .${resetClass}{
        overflow:hidden;
        padding:0;
      }
      .${resetClass}>*{
        display: none;
      }
      #root{
        display: block;
        width: 100vw;
        height: 100svh;
        margin:0;
        padding:0;
        background-color:transparent;
      }
    </style>
    `;
  $('head').append(styleTag);

  // Always load base SPARC theme (not configurable)
  const baseCssPath = resolvePath(`@/libs/${SPARC_PREFIX}/${SPARC_PREFIX}.base.css`);
  $('head').append(`<link rel="stylesheet" href="${baseCssPath}" />`);

  // Load client/app theme on top (optional)
  if (themePath) {
    $('head').append(`<link rel="stylesheet" href="${themePath}" />`);
  }
}
