import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { HTMDElement, HTMDElementProps } from '../../abstracts/HTMDElement.abstract';

export interface LoaderProps extends HTMDElementProps {
  animation?: 'pulse';
}

export class Loader extends HTMDElement {
  animation?: 'pulse';
  constructor(children: HTMDNode, props: LoaderProps) {
    super(children, props);
    this.animation = props?.animation || 'pulse';
  }

  toString() {
    return `<div id="${this.id}" ${this.animation ? `data-animation=${this.animation}` : ''} class="${this.class}" />`;
  }

  toggleLoader() {
    if (this.isAlive)
      this.instance?.fadeOut('slow', () => {
        this.remove();
      });
    else {
      this.render();
      this.instance?.hide();
      this.instance?.fadeIn('slow');
    }
  }
}
