import { FormField } from '../../../../utils/form/FormField.class';
import { FormControl } from '../../../abstracts/FormControl.abstract';

export interface NumberInputProps extends FormControl<number> {
  min?: number;
  step?: number;
  max?: number;
}

export class NumberInput extends FormControl<number> {
  public min?: number;
  public step?: number;
  public max?: number;

  constructor(fieldOrValue: number | FormField<number>, props: NumberInputProps) {
    super(fieldOrValue, props);
    this.min = props?.min;
    this.step = props?.step;
    this.max = props?.max;
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();

    this.setEventHandler('blur', () => {
      this._value.value = this.instance?.val() as number;
      if (this._value.wasTouched) {
        this._validate();
      }
    });
  }

  toString() {
    const addAttrFromProp = (prop: keyof NumberInput & string) =>
      this[prop] ? `${prop}=${this[prop]}` : '';
    return `<input 
                    title="${this.value}"
                    id="${this.id}"
                    class="${this.class} ${super.modifierClasses}"
                    type="number"
                    autocomplete="off"
                    tabindex=0
                    ${this.isDisabled ? 'disabled' : ''}
                    value="${this._value.value}"
                    ${addAttrFromProp('min')}
                    ${addAttrFromProp('step')}
                    ${addAttrFromProp('max')}
                    />`;
  }
}
