import { spGET, spPOST } from './httpRequests';
import type { SiteApi } from './SiteApi.class';
import type {
  FullUserDetails,
  PeopleSearchOptions,
  PeopleSearchResult,
  ProfileProperty,
  SPGroup,
  SPUser,
  UserProfile,
  UserProfilePayload,
} from '../../types/sharepoint/people.types';

// -- Private helpers --

function _buildSearchPayload(query: string, options: PeopleSearchOptions): object {
  return {
    queryParams: {
      // eslint-disable-next-line @typescript-eslint/naming-convention
      __metadata: { type: 'SP.UI.ApplicationPages.ClientPeoplePickerQueryParameters' },
      // eslint-disable-next-line @typescript-eslint/naming-convention
      QueryString: query,
      // eslint-disable-next-line @typescript-eslint/naming-convention
      MaximumEntitySuggestions: options.maximumSuggestions ?? 10,
      // eslint-disable-next-line @typescript-eslint/naming-convention
      PrincipalType: options.principalType ?? 1,
      // eslint-disable-next-line @typescript-eslint/naming-convention
      PrincipalSource: options.principalSource ?? 15,
      // eslint-disable-next-line @typescript-eslint/naming-convention
      AllowEmailAddresses: true,
      // eslint-disable-next-line @typescript-eslint/naming-convention
      AllowMultipleEntities: true,
      // eslint-disable-next-line @typescript-eslint/naming-convention
      SharePointGroupID: 0,
    },
  };
}

/**
 * Strips the SharePoint REST response envelope, normalizing both OData formats:
 *
 * - verbose:    `{ d: T }` -> `T`
 * - nometadata: `{ value: T }` -> `T`  (only when `value` is NOT an array;
 *               array `value` is a collection left for {@link _unwrapCollection})
 * - bare entity (nometadata, no wrapper): returned as-is
 */
function _unwrapD<T>(data: unknown): T {
  if (data !== null && typeof data === 'object') {
    const obj = data as Record<string, unknown>;
    if ('d' in obj) return obj.d as T;
    if ('value' in obj && !Array.isArray(obj.value)) return obj.value as T;
  }
  return data as T;
}

function _unwrapCollection<T>(data: unknown): T[] {
  if (!data) return [];
  if (Array.isArray(data)) return data;
  if (typeof data === 'object') {
    const obj = data as Record<string, unknown>;
    if (Array.isArray(obj.results)) return obj.results;
    if (Array.isArray(obj.value)) return obj.value;
  }
  return [];
}

async function _resolveLoginName(login: string): Promise<string> {
  if (login.startsWith('i:')) return login;

  const results = await searchUsers(login, { maximumSuggestions: 10 });
  if (results.length === 0) return login;
  if (results.length === 1) return results[0].Key;

  // Multiple matches -- disambiguate

  // Strategy A: match the current session's auth provider prefix
  const currentLogin: string = _spPageContextInfo?.userLoginName ?? '';
  const prefixMatch = currentLogin.match(/^(i:[^|]+\|)/);
  if (prefixMatch) {
    const currentPrefix = prefixMatch[1];
    const sameProvider = results.find(
      (r) => r.Key.startsWith(currentPrefix) && r.IsResolved
    );
    if (sameProvider) return sameProvider.Key;
  }

  // Strategy B: fall back to first resolved entry
  const resolved = results.find((r) => r.IsResolved);
  if (resolved) return resolved.Key;

  return results[0].Key;
}

async function _fetchProfile(
  loginName: string,
  siteUrl: string
): Promise<UserProfilePayload> {
  const encodedLogin = encodeURIComponent(`'${loginName}'`);
  const endpoint =
    `${siteUrl}/_api/SP.UserProfiles.PeopleManager` +
    `/GetPropertiesFor(accountName=@v)?@v=${encodedLogin}`;
  const data = await spGET(endpoint);
  return _unwrapD<UserProfilePayload>(data);
}

async function _ensureUser(loginName: string, siteApi: SiteApi): Promise<SPUser> {
  const digest = await siteApi.getRequestDigest();
  const endpoint = `${siteApi.url}/_api/web/ensureuser`;
  const data = await spPOST(endpoint, {
    requestDigest: digest,
    data: { logonName: loginName },
  });
  return _unwrapD<SPUser>(data);
}

async function _fetchUserGroups(userId: number, siteUrl: string): Promise<SPGroup[]> {
  const endpoint = `${siteUrl}/_api/web/getuserbyid(${userId})/groups`;
  const data = await spGET(endpoint);
  return _unwrapCollection<SPGroup>(_unwrapD(data));
}

// -- Exported utilities --

/**
 * Extracts the samAccountName (employee ID) from a SharePoint claims login string.
 *
 * SharePoint claims-encoded logins follow the pattern `i:0#.w|DOMAIN\username`.
 * This function strips the claims prefix and domain, returning only the username portion.
 *
 * @param loginName - A claims-encoded or plain login string.
 * @returns The samAccountName portion (e.g. `"rlopes"` from `"i:0#.w|DOMAIN\\rlopes"`).
 */
export function parseEmployeeId(loginName: string): string {
  const afterPipe = loginName.includes('|') ? loginName.split('|').pop()! : loginName;
  return afterPipe.includes('\\') ? afterPipe.split('\\').pop()! : afterPipe;
}

// -- Exported functions --

/**
 * Searches Active Directory for users matching the given query string.
 *
 * Uses the `clientPeoplePickerSearchUser` endpoint which performs a farm-wide
 * search against all configured identity providers. Reads
 * `_spPageContextInfo.webAbsoluteUrl` for the endpoint URL; the request digest
 * is auto-injected by {@link spPOST}.
 *
 * @param query - The search string (name, email, or login name).
 * @param options - Optional search configuration. See {@link PeopleSearchOptions}.
 * @returns An array of matching {@link PeopleSearchResult} entries.
 */
export async function searchUsers(
  query: string,
  options: PeopleSearchOptions = {}
): Promise<PeopleSearchResult[]> {
  const payload = _buildSearchPayload(query, options);
  const endpoint =
    `${_spPageContextInfo.webAbsoluteUrl}/_api/SP.UI.ApplicationPages` +
    `.ClientPeoplePickerWebServiceInterface.clientPeoplePickerSearchUser`;

  const data = await spPOST(endpoint, { data: payload });
  // verbose: { d: { ClientPeoplePickerSearchUser: "..." } } -> unwrapD strips d
  // nometadata: { value: "..." } -> unwrapD strips value -> string directly
  const unwrapped = _unwrapD<Record<string, string> | string>(data);
  const raw = typeof unwrapped === 'string'
    ? unwrapped
    : unwrapped.ClientPeoplePickerSearchUser;
  return JSON.parse(raw) as PeopleSearchResult[];
}

/**
 * Retrieves the user profile from PeopleManager (farm-wide, no site context needed).
 *
 * Accepts a claims login name (e.g. `"i:0#.w|DOMAIN\\user"`) or a plain
 * `DOMAIN\\user` string. If the input lacks a claims prefix, the function
 * resolves the full claims identity via people picker search.
 *
 * @param loginName - The user's login name (claims-encoded or plain DOMAIN\\user).
 * @returns A {@link UserProfile} object with profile data.
 * @throws When the profile cannot be fetched.
 */
export async function getUserProfile(loginName: string): Promise<UserProfile> {
  const normalizedLogin = await _resolveLoginName(loginName);
  const profile = await _fetchProfile(normalizedLogin, _spPageContextInfo.webAbsoluteUrl);

  return {
    employeeId: parseEmployeeId(normalizedLogin),
    loginName: normalizedLogin,
    displayName: profile.DisplayName ?? '',
    email: profile.Email ?? '',
    jobTitle: profile.Title ?? '',
    pictureUrl: profile.PictureUrl ?? '',
    personalUrl: profile.PersonalUrl ?? '',
    directReports: _unwrapCollection<string>(profile.DirectReports),
    managers: _unwrapCollection<string>(profile.ExtendedManagers),
    peers: _unwrapCollection<string>(profile.Peers),
    profileProperties: Object.fromEntries(
      _unwrapCollection<ProfileProperty>(profile.UserProfileProperties)
        .filter((p) => p.Value)
        .map((p) => [p.Key, p.Value])
    ),
  };
}

/**
 * Retrieves consolidated user details from multiple SharePoint endpoints.
 *
 * Site-scoped -- requires a {@link SiteApi} instance for cross-site digest
 * management and endpoint resolution.
 *
 * Accepts a claims login name (e.g. `"i:0#.w|DOMAIN\\user"`) or a plain
 * `DOMAIN\\user` string. If the input lacks a claims prefix, the function
 * resolves the full claims identity via people picker search.
 *
 * The pipeline calls three endpoints:
 * 1. `ensureUser` (POST) -- registers the user on the site, returns site-level ID
 * 2. `getuserbyid/groups` (GET) -- returns SharePoint group memberships
 * 3. `PeopleManager/GetPropertiesFor` (GET) -- returns full user profile
 *
 * Steps 2 and 3 are fault-tolerant: if either fails, the corresponding
 * fields are populated with empty defaults rather than aborting the entire call.
 *
 * @param loginName - The user's login name (claims-encoded or plain DOMAIN\\user).
 * @param siteApi - A {@link SiteApi} instance for site-scoped operations.
 * @returns A consolidated {@link FullUserDetails} object.
 * @throws When `ensureUser` fails (user cannot be resolved on the site).
 */
export async function getFullUserDetails(
  loginName: string,
  siteApi: SiteApi
): Promise<FullUserDetails> {
  const normalizedLogin = await _resolveLoginName(loginName);

  // Step 1: ensureUser -- required, throw on failure
  const spUser = await _ensureUser(normalizedLogin, siteApi);

  // Step 2: groups -- optional, empty array on failure
  let groups: SPGroup[] = [];
  try {
    groups = await _fetchUserGroups(spUser.Id, siteApi.url);
  } catch {
    /* swallow -- groups are non-critical */
  }

  // Step 3: profile -- optional, partial data on failure
  let profile: UserProfilePayload | null = null;
  try {
    profile = await _fetchProfile(normalizedLogin, siteApi.url);
  } catch {
    /* swallow -- profile is non-critical */
  }

  return {
    employeeId: parseEmployeeId(spUser.LoginName),
    loginName: spUser.LoginName,
    displayName: profile?.DisplayName ?? spUser.Title,
    email: profile?.Email || spUser.Email,
    siteUserId: spUser.Id,
    jobTitle: profile?.Title ?? '',
    pictureUrl: profile?.PictureUrl ?? '',
    personalUrl: profile?.PersonalUrl ?? '',
    directReports: _unwrapCollection<string>(profile?.DirectReports),
    managers: _unwrapCollection<string>(profile?.ExtendedManagers),
    peers: _unwrapCollection<string>(profile?.Peers),
    groups,
    profileProperties: Object.fromEntries(
      _unwrapCollection<ProfileProperty>(profile?.UserProfileProperties)
        .filter((p) => p.Value)
        .map((p) => [p.Key, p.Value])
    ),
  };
}
