import { forEach } from 'lodash';
import { SystemError } from '../../../error-handling/errors/SystemError';
import {
  HTMDElementInterface,
  isHTMDComponent,
} from '../../abstracts/HTMDElementInterface.interface';

export interface FragmentProps {
  containerSelector?: string;
}

/**
 * A fragment is just an HTMDElement that renders multiple children without wrapping them on another element.
 *
 * Contrary to regular HTMDElements, a fragment can't contain all types of HTMDNode,
 * since Fragment will not act as a parent node in the DOM, it needs an implementation of the
 * HTMDElementInterface
 *
 * @see HTMDElementInterface
 */
export class Fragment implements HTMDElementInterface {
  isHTMD: true;
  protected _children: HTMDElementInterface[];
  protected _containerSelector?: string;
  constructor(children: HTMDElementInterface[], props?: FragmentProps) {
    this._children = children;
    this._containerSelector = props?.containerSelector;
    this.isHTMD = true;
  }

  get [Symbol.toStringTag]() {
    return 'Fragment';
  }

  protected _renderChild(child: HTMDElementInterface) {
    if (!isHTMDComponent(child))
      throw new SystemError(
        'Invalid child',
        'Fragment received a child that does not implement HTMDElementInterface. Only SPARC components are valid Fragment children.'
      );
    if (this._containerSelector) child.containerSelector = this._containerSelector;
    child.render();
  }

  render() {
    forEach(this._children, (child) => this._renderChild(child));
  }
  remove() {
    forEach(this._children, (child) => child?.remove());
  }
  toString(): string {
    let str = '';
    forEach(this._children, (e) => (str += e.toString()));
    return str;
  }

  //========================================================

  get children(): HTMDElementInterface[] {
    return this._children;
  }

  get containerSelector(): string | undefined {
    return this._containerSelector;
  }

  set children(children: HTMDElementInterface[]) {
    this._children = children;
  }

  set containerSelector(selector: string) {
    this.remove();
    this._containerSelector = selector;
  }
}
