import { generateRuntimeUID } from '../utils/misc/identity';
import { BreakingErrorDialog } from '../DOM/components/feedback/BreakingErrorDialog';
import { SystemError } from './errors/SystemError';

export interface ErrorBoundaryProps {
  target?: Window | HTMLElement;
  onErrorCallback?: (error: ErrorEvent) => void;
  onAsyncErrorCallback?: (error: PromiseRejectionEvent) => void;
  name?: string;
}

export class ErrorBoundary {
  protected _targetElement: Window | HTMLElement;
  protected _onErrorCallback?: (error: ErrorEvent) => void;
  protected _onAsyncErrorCallback?: (error: PromiseRejectionEvent) => void;
  protected _name: string;
  constructor(props: ErrorBoundaryProps) {
    this._targetElement = props?.target || window;
    this._onErrorCallback = props?.onErrorCallback;
    this._onAsyncErrorCallback = props?.onAsyncErrorCallback;
    this._name = props?.name || generateRuntimeUID(`error-boundary`);
    this._addEventListeners();
  }

  protected async _displayError(error: SystemError) {
    if (error.breaksFlow) {
      new BreakingErrorDialog(error).render();
    } else {
      console.error(error); // TODO display alerts/toasts
    }
  }

  protected _parseEventData(event: Event) {
    if (event instanceof ErrorEvent && event.error instanceof Error) {
      return SystemError.fromErrorEvent(event);
    } else {
      return new SystemError(`Unknown Error`, 'ErrorBoundary was triggered by an unknown event');
    }
  }

  private _onErrorEventHandler() {
    this._targetElement.addEventListener('error', (e) => {
      console.warn(`Error caught by ${this._name} ErrorBoundary`);
      console.error(e);

      const error = this._parseEventData(e);
      this._displayError(error);

      e.preventDefault();
      if (this._onErrorCallback) this._onErrorCallback(e as ErrorEvent);
    });
  }

  private _onAsyncErrorEventHandler() {
    this._targetElement.addEventListener('unhandledrejection', (e) => {
      console.warn(`Unhandled promise rejection caught by ${this._name} ErrorBoundary`);
      reportError((e as PromiseRejectionEvent).reason);
      if (this._onAsyncErrorCallback) this._onAsyncErrorCallback(e as PromiseRejectionEvent);
    });
  }

  private _addEventListeners() {
    this._onErrorEventHandler();
    this._onAsyncErrorEventHandler();
  }
}
