import { SystemError } from '../../error-handling/errors/SystemError';
import { normalizeUrl } from '../../utils/misc/url';

/**
 * Response shape for the `/_api/contextinfo` endpoint (odata=nometadata format).
 *
 * With `odata=nometadata`, the response omits the `d` wrapper present in verbose
 * mode, so `GetContextWebInformation` is a top-level property.
 */
interface ContextInfoResponse {
  // eslint-disable-next-line @typescript-eslint/naming-convention
  GetContextWebInformation: {
    // eslint-disable-next-line @typescript-eslint/naming-convention
    FormDigestValue: string;
    // eslint-disable-next-line @typescript-eslint/naming-convention
    FormDigestTimeoutSeconds: number;
  };
}

/** Per-site in-flight coalescing map. Non-null entries exist while a digest refresh is pending for that URL. */
const _pendingRefreshes = new Map<string, Promise<string>>();

/** Cached remote tokens with pre-computed expiry timestamps. */
const _remoteTokenCache = new Map<string, { token: string; expiresAt: number }>();

/**
 * Fetches a fresh form digest token from SharePoint's `/_api/contextinfo` endpoint.
 *
 * Supports both local and remote sites:
 *
 * - **Local** (no `siteUrl`, or `siteUrl` matches `_spPageContextInfo.webAbsoluteUrl`):
 *   Fetches a new token, updates the `#__REQUESTDIGEST` hidden field in the DOM, and
 *   returns the token. This ensures all subsequent readers pick up the new value.
 *
 * - **Remote** (a different `siteUrl`):
 *   Checks an in-memory cache first. If a valid cached token exists, returns it
 *   immediately without an API call. Otherwise fetches a new token, caches it with a
 *   60-second safety buffer before the server-reported expiry, and returns it. The DOM
 *   `#__REQUESTDIGEST` field is NOT updated for remote tokens.
 *
 * Uses per-site request coalescing: if multiple callers invoke this function for the
 * same site while a refresh is already in flight, they all receive the same Promise.
 * The in-flight reference is cleared once the request settles (success or failure).
 *
 * Requests use `odata=nometadata` Accept headers. The response arrives without
 * the `d` wrapper, so `GetContextWebInformation` is parsed directly from the
 * top-level response object.
 *
 * This function calls `$.ajax` directly instead of {@link baseRequest} to avoid
 * recursive retry loops (baseRequest calls this function on digest expiry).
 *
 * @param siteUrl - Optional absolute URL of the target site. When omitted or matching
 *   the local site, the local digest flow is used.
 *
 * @returns A Promise that resolves with the digest token string.
 *
 * @throws {SystemError} With name `"APIException: RequestDigestRefresh"` if the
 *   contextinfo request fails.
 */
export function refreshRequestDigest(siteUrl?: string): Promise<string> {
  const localUrl = _spPageContextInfo.webAbsoluteUrl;
  const normalizedLocal = normalizeUrl(localUrl);
  const targetUrl = siteUrl ?? localUrl;
  const normalizedTarget = normalizeUrl(targetUrl);
  const isLocal = normalizedTarget === normalizedLocal;

  // Remote: check cache first
  if (!isLocal) {
    const cached = _remoteTokenCache.get(normalizedTarget);
    if (cached && Date.now() < cached.expiresAt) {
      return Promise.resolve(cached.token);
    }
  }

  // Coalesce concurrent requests for the same site
  const pending = _pendingRefreshes.get(normalizedTarget);
  if (pending) return pending;

  const promise = new Promise<string>((resolve, reject) => {
    $.ajax({
      url: targetUrl + '/_api/contextinfo',
      type: 'POST',
      headers: {
        accept: 'application/json;odata=nometadata',
      },
      dataType: 'json',
    })
      .done((res: ContextInfoResponse) => {
        const info = res.GetContextWebInformation;
        const token = info.FormDigestValue;

        if (isLocal) {
          _spPageContextInfo.formDigestValue = token;
          _spPageContextInfo.formDigestTimeoutSeconds = info.FormDigestTimeoutSeconds;
          $('#__REQUESTDIGEST').val(token);
        } else {
          const timeoutSeconds = info.FormDigestTimeoutSeconds;
          _remoteTokenCache.set(normalizedTarget, {
            token,
            expiresAt: Date.now() + (timeoutSeconds - 60) * 1000,
          });
        }

        resolve(token);
      })
      .fail((jqXHR: JQueryXHR) => {
        const status = jqXHR.status ?? 0;
        const detail = jqXHR.responseText ?? jqXHR.statusText ?? 'Unknown error';
        reject(
          new SystemError(
            'APIException: RequestDigestRefresh',
            `HTTP ${status} -- ${detail}`
          )
        );
      });
  }).finally(() => {
    _pendingRefreshes.delete(normalizedTarget);
  });

  _pendingRefreshes.set(normalizedTarget, promise);
  return promise;
}
