import { HTMDElement, HTMDElementProps } from '../../abstracts/HTMDElement.abstract';

export interface ImageProps extends HTMDElementProps {
  alt?: string;
  onLoad?: () => void;
}

export class Image extends HTMDElement {
  private _src: string;
  private _alt?: string;
  private _onLoadCallback: () => void;
  constructor(src: string, props: ImageProps) {
    super(undefined, props);
    this._src = src;
    this._alt = props?.alt;
    this._onLoadCallback = props?.onLoad || (() => {});
  }

  private _preloader() {
    // const classThis = this;
    const $imgElement = this.instance?.find('img');

    if (!$imgElement) return; //IMPROVE: throw propererror here

    $imgElement.on('load', () => {
      this.instance?.css('opacity', '1');
      this._onLoadCallback();
    });

    $imgElement.on('error', function () {
      console.error('Failed to load image');
    });

    $imgElement.attr('src', this._src);
  }

  render(_shouldRenderChildren?: boolean): void {
    super.render(false);
    this._preloader();
  }

  toString(): string {
    return `<div id="${this.id}" class="${this.class}"> <img alt="${this._alt}"/> </div>`;
  }
}
