import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { Container, ContainerProps } from './Container';

export type CardVariants = 'primary' | 'secondary';

export interface CardProps extends ContainerProps {
  /** Defines the element styling variant. Defaults to "primary" */
  variant?: CardVariants;
}

export class Card extends Container {
  public variant: CardVariants;
  constructor(children: HTMDNode, props?: CardProps) {
    super(children, props);
    this.variant = props?.variant || 'primary';
  }

  protected get _modifierClasses() {
    const superMods: string[] = [super._modifierClasses];
    superMods.push(`${this.topClassBEM}--${this.variant}`);
    return superMods.join(' ');
  }
}
