import { HTMDElement, HTMDElementProps } from '../../../abstracts/HTMDElement.abstract';
import { getIcon } from '../../media/Icon';
import { CheckBox } from '../toggles/Checkbox';

export type FieldLabelPosition = 'left' | 'top' | 'right' | 'bottom';

export interface FieldLabelProps extends HTMDElementProps {
  /**
   * Position of the label relative to the wrapped component
   * @default 'top'
   */
  position?: FieldLabelPosition;

  /**
   * Tooltip text to display on hover
   */
  tooltip?: string;
}

/**
 * FieldLabel component that wraps any HTMDElement with a label.
 * Provides flexible positioning and optional tooltip functionality.
 *
 * @example
 * ```typescript
 * const input = new TextInput('', { placeholder: 'Enter your name' });
 * const field = new FieldLabel('Full Name', input, {
 *   position: 'top',
 *   tooltip: 'Please enter your full legal name'
 * });
 * field.render();
 * ```
 */
export class FieldLabel extends HTMDElement {
  private _labelText: string;
  private _position: FieldLabelPosition;
  private _tooltip?: string;
  private _componentId?: string;

  constructor(labelText: string, component: HTMDElement, props?: FieldLabelProps) {
    super(component, props);
    this._labelText = labelText;
    this._position = props?.position || (component instanceof CheckBox ? 'left' : 'top');
    this._tooltip = props?.tooltip;
    this._componentId = component.id;
  }

  get [Symbol.toStringTag]() {
    return 'Field Label';
  }

  get modifierClasses(): string {
    return `${this.topClassBEM}--${this._position}`;
  }

  /**
   * Generates the label HTML with optional tooltip
   */
  private _createLabel(): string {
    const tooltipAttr = this._tooltip ? `title="${this._tooltip}"` : '';
    const tooltipIcon = this._tooltip
      ? `<span class="${this.topClassBEM}__tooltip-icon" aria-label="More information">${getIcon('information-line')}</span>`
      : '';

    return `
      <label 
        class="${this.topClassBEM}__label" 
        for="${this._componentId}"
        ${tooltipAttr}
      >
        <span class="${this.topClassBEM}__label-text">${this._labelText}</span>
        ${tooltipIcon}
      </label>
    `;
  }

  toString(): string {
    return `
      <div
        id="${this.id}"
        class="${this.class} ${this.modifierClasses}"
      >
        <div class="${this.topClassBEM}__wrapper">
          ${this._createLabel()}
          <div class="${this.topClassBEM}__component-container"></div>
         </div>
      </div>
    `;
  }

  render(): void {
    super.render(true, { childrenContainerSelector: `.${this.topClassBEM}__component-container` });
  }

  /**
   * Updates the label text
   */
  set label(text: string) {
    this._labelText = text;
    this.instance?.find(`.${this.topClassBEM}__label-text`)?.text(text);
  }

  /**
   * Updates the tooltip text
   */
  set tooltip(tooltip: string | undefined) {
    this._tooltip = tooltip;
    $(`.${this.topClassBEM}__label`).replaceWith(this._createLabel());
  }

  /**
   * Updates the position of the label
   */
  set position(position: FieldLabelPosition) {
    if (this._position === position) return;
    this._position = position;

    if (this.isAlive) {
      // Remove old position class and add new one
      this.instance?.removeClass(
        `${this.topClassBEM}--left ${this.topClassBEM}--top ${this.topClassBEM}--right ${this.topClassBEM}--bottom`
      );
      this.instance?.addClass(`${this.topClassBEM}--${position}`);
    }

    this.render();
  }

  /**
   * Gets the label text
   */
  get label(): string {
    return this._labelText;
  }

  /**
   * Gets the current position
   */
  get position(): FieldLabelPosition {
    return this._position;
  }

  /**
   * Gets the tooltip text
   */
  get tooltip(): string | undefined {
    return this._tooltip;
  }
}
