import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat';
import { FormField } from '../../../../utils/form/FormField.class';
import { FormControl, FormControlProps } from '../../../abstracts/FormControl.abstract';
import { getIcon } from '../../media/Icon';

dayjs.extend(customParseFormat);

// ============================================================ TYPES

export type DATE_FORMATS = 'dd-mm-yyyy' | 'mm-dd-yyyy' | 'yyyy-mm-dd';

export interface DateInputProps extends FormControlProps {
  format?: DATE_FORMATS;
  placeholder?: string;
}

// ============================================================ FORMAT MAP

/* eslint-disable @typescript-eslint/naming-convention */
const FORMAT_MAP: Record<DATE_FORMATS, string> = {
  'dd-mm-yyyy': 'DD-MM-YYYY',
  'mm-dd-yyyy': 'MM-DD-YYYY',
  'yyyy-mm-dd': 'YYYY-MM-DD',
};
/* eslint-enable @typescript-eslint/naming-convention */

// ============================================================ CLASS

export class DateInput extends FormControl<string> {
  public format: DATE_FORMATS;

  private _placeholder: string;
  private _dayjsFormat: string;
  private _viewDate: dayjs.Dayjs;
  private _selectedDate: dayjs.Dayjs | null;
  private _isCalendarOpen: boolean;
  private _pendingTimeouts: Set<ReturnType<typeof setTimeout>> = new Set();

  constructor(fieldOrValue: string | FormField<string>, props: DateInputProps = {}) {
    super(fieldOrValue, props);
    this.format = props.format ?? 'dd-mm-yyyy';
    this._placeholder = props.placeholder ?? this.format.toUpperCase();
    this._dayjsFormat = FORMAT_MAP[this.format];
    this._viewDate = dayjs();
    this._selectedDate = null;
    this._isCalendarOpen = false;
  }

  // ============================================================ TIMEOUT TRACKING

  private _trackTimeout(fn: () => void, ms: number): ReturnType<typeof setTimeout> {
    const id = setTimeout(() => {
      this._pendingTimeouts.delete(id);
      fn();
    }, ms);
    this._pendingTimeouts.add(id);
    return id;
  }

  private _clearAllTimeouts(): void {
    this._pendingTimeouts.forEach(clearTimeout);
    this._pendingTimeouts.clear();
  }

  // ============================================================ HTML BUILDERS

  private _createCalendarPanel(): string {
    return `<div class="${this.topClassBEM}__calendar" style="display:none">
      <div class="${this.topClassBEM}__calendar__header">
        <button class="${this.topClassBEM}__calendar__prev" type="button">${getIcon('arrow-left-s-line')}</button>
        <span class="${this.topClassBEM}__calendar__title">${this._viewDate.format('MMMM YYYY')}</span>
        <button class="${this.topClassBEM}__calendar__next" type="button">${getIcon('arrow-right-s-line')}</button>
      </div>
      <table class="${this.topClassBEM}__calendar__grid">
        <thead>
          <tr>
            <th>Su</th><th>Mo</th><th>Tu</th><th>We</th><th>Th</th><th>Fr</th><th>Sa</th>
          </tr>
        </thead>
        <tbody>${this._createCalendarBody()}</tbody>
      </table>
      <div class="${this.topClassBEM}__calendar__footer">
        <button class="${this.topClassBEM}__calendar__today" type="button">Today</button>
      </div>
    </div>`;
  }

  private _createCalendarBody(): string {
    const firstOfMonth = this._viewDate.startOf('month');
    const daysInMonth = this._viewDate.daysInMonth();
    const startWeekday = firstOfMonth.day(); // 0 = Sunday

    const today = dayjs();
    const bemDay = `${this.topClassBEM}__calendar__day`;
    let html = '<tr>';
    let cellCount = 0;

    // Empty padding cells before day 1
    for (let i = 0; i < startWeekday; i++) {
      html += `<td class="${bemDay} ${bemDay}--empty"></td>`;
      cellCount++;
    }

    // Day cells
    for (let day = 1; day <= daysInMonth; day++) {
      const currentDate = this._viewDate.date(day);
      const dateStr = currentDate.format('YYYY-MM-DD');
      const mods: string[] = [];

      if (currentDate.isSame(today, 'day')) {
        mods.push(`${bemDay}--today`);
      }
      if (this._selectedDate && currentDate.isSame(this._selectedDate, 'day')) {
        mods.push(`${bemDay}--selected`);
      }

      html += `<td class="${bemDay} ${mods.join(' ')}" data-date="${dateStr}">${day}</td>`;
      cellCount++;

      if (cellCount % 7 === 0 && day < daysInMonth) {
        html += '</tr><tr>';
      }
    }

    // Fill remaining cells in last row
    const remaining = cellCount % 7;
    if (remaining > 0) {
      for (let i = remaining; i < 7; i++) {
        html += `<td class="${bemDay} ${bemDay}--empty"></td>`;
      }
    }

    html += '</tr>';
    return html;
  }

  // ============================================================ CALENDAR CONTROL

  private _openCalendar(): void {
    this._refreshCalendarContent();
    this.instance?.addClass(`${this.topClassBEM}--open`);
    this.instance?.find(`.${this.topClassBEM}__calendar`).slideDown();
    this._isCalendarOpen = true;
  }

  private _closeCalendar(): void {
    this.instance?.find(`.${this.topClassBEM}__calendar`).slideUp();
    const duration = 300;
    this._trackTimeout(() => this.instance?.removeClass(`${this.topClassBEM}--open`), duration);
    this._isCalendarOpen = false;
  }

  private _refreshCalendarContent(): void {
    this.instance
      ?.find(`.${this.topClassBEM}__calendar__title`)
      .text(this._viewDate.format('MMMM YYYY'));
    this.instance
      ?.find(`.${this.topClassBEM}__calendar__grid tbody`)
      .html(this._createCalendarBody());
    this._bindDayClickHandlers();
  }

  // ============================================================ VALUE SYNC

  private _syncValueFromInput(): void {
    const input = this.instance?.find(`.${this.topClassBEM}__input`);
    const raw = input?.val()?.toString() ?? '';

    if (!raw) {
      this._selectedDate = null;
      this._value.value = '';
    } else {
      const parsed = dayjs(raw, this._dayjsFormat, true);
      if (parsed.isValid()) {
        this._selectedDate = parsed;
        this._viewDate = parsed;
        this._value.value = parsed.format(this._dayjsFormat);
        input?.val(this._value.value);
      } else {
        // Store raw text so the validator can reject it
        this._selectedDate = null;
        this._value.value = raw;
      }
    }
    if (this._value.wasTouched) this._validate();
  }

  private _applyDateSelection(date: dayjs.Dayjs): void {
    this._selectedDate = date;
    this._viewDate = date;
    this._value.value = date.format(this._dayjsFormat);
    this._closeCalendar();
    this.instance?.find(`.${this.topClassBEM}__input`).val(this._value.value);
    if (this._value.wasTouched) this._validate();
  }

  // ============================================================ EVENT BINDINGS

  private _bindDayClickHandlers(): void {
    const bemDay = `${this.topClassBEM}__calendar__day`;
    this.instance?.find(`.${bemDay}:not(.${bemDay}--empty)`).each((_, el) => {
      $(el).on('click', (e) => {
        e.stopPropagation();
        const dateStr = $(el).attr('data-date');
        if (dateStr) this._applyDateSelection(dayjs(dateStr));
      });
    });
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();

    // Click on input wrapper opens calendar
    this.instance?.find(`.${this.topClassBEM}__input-wrapper`).on('click', () => {
      if (!this._isDisabled && !this._isCalendarOpen) this._openCalendar();
    });

    // Blur with timeout syncs typed value (allows click events on calendar to fire first)
    const input = this.instance?.find(`.${this.topClassBEM}__input`);
    input?.on('blur', () => {
      this._trackTimeout(() => this._syncValueFromInput(), 150);
    });

    // Escape closes calendar
    this.instance?.on('keydown', (e) => {
      if (e.originalEvent?.key === 'Escape') this._closeCalendar();
    });

    // Prev month button
    this.instance?.find(`.${this.topClassBEM}__calendar__prev`).on('click', (e) => {
      e.stopPropagation();
      this._viewDate = this._viewDate.subtract(1, 'month');
      this._refreshCalendarContent();
    });

    // Next month button
    this.instance?.find(`.${this.topClassBEM}__calendar__next`).on('click', (e) => {
      e.stopPropagation();
      this._viewDate = this._viewDate.add(1, 'month');
      this._refreshCalendarContent();
    });

    // Day click handlers (initial bind)
    this._bindDayClickHandlers();

    // Today button
    this.instance?.find(`.${this.topClassBEM}__calendar__today`).on('click', (e) => {
      e.stopPropagation();
      this._applyDateSelection(dayjs());
    });

    // Focusout handler -- close calendar when focus leaves the component
    this.instance?.on('focusout', () => {
      this._trackTimeout(() => {
        const active = document.activeElement;
        if (!this.instance?.[0]?.contains(active)) {
          this._closeCalendar();
        }
      }, 0);
    });
  }

  // ============================================================ DISPLAY

  get modifierClasses(): string {
    const mods = [super.modifierClasses];
    if (this._isCalendarOpen) mods.push(`${this.topClassBEM}--open`);
    return mods.join(' ');
  }

  toString(): string {
    return `<div
      id="${this.id}"
      class="${this.class} ${this.modifierClasses}"
      tabindex="-1"
    >
      <div class="${this.topClassBEM}__input-wrapper">
        <input
          class="${this.topClassBEM}__input"
          type="text"
          autocomplete="off"
          placeholder="${this._placeholder}"
          value="${this._selectedDate ? this._selectedDate.format(this._dayjsFormat) : this._value.value}"
          ${this._isDisabled ? 'disabled' : ''}
        />
        <span class="${this.topClassBEM}__icon">
          ${getIcon('calendar-line')}
        </span>
      </div>
      ${this._createCalendarPanel()}
    </div>`;
  }

  // ============================================================ LIFECYCLE

  render(): void {
    super.render(false);
  }

  remove(): void {
    this._clearAllTimeouts();
    super.remove();
  }
}
