import { debounce } from 'lodash';
import { ComboBox, ComboBoxOptionProps, ComboBoxProps } from './ComboBox';
import { searchUsers } from '../../../../sharepoint/api/people.api';
import { FormField } from '../../../../utils/form/FormField.class';
import type {
  PeopleSearchOptions,
  PeopleSearchResult,
} from '../../../../types/sharepoint/people.types';

export interface PeoplePickerProps
  extends Omit<ComboBoxProps, 'filteringFunction' | 'allowMultiple' | 'allowFiltering' | 'allowCreate'> {
  /** Debounce delay in milliseconds before firing a search request. @default 300 */
  debounceMs?: number;
  /** Minimum number of characters required before searching. @default 2 */
  minimumCharacters?: number;
  /** Maximum number of results to return from the people picker endpoint. */
  maximumSuggestions?: number;
  /** Bitmask controlling which principal types to search. @default 1 (User) */
  principalType?: number;
  /** Bitmask controlling which identity sources to search. @default 15 (All) */
  principalSource?: number;
}

export class PeoplePicker extends ComboBox {
  private _minimumCharacters: number;
  private _searchOptions: PeopleSearchOptions;
  private _debouncedSearch: ReturnType<typeof debounce>;
  private _lastSearchResults: PeopleSearchResult[] = [];

  constructor(field: FormField<ComboBoxOptionProps | ComboBoxOptionProps[]>, props: PeoplePickerProps) {
    const {
      debounceMs,
      minimumCharacters,
      maximumSuggestions,
      principalType,
      principalSource,
      ...comboBoxProps
    } = props;

    super(field, [], {
      ...comboBoxProps,
      allowFiltering: true,
      allowMultiple: false,
    });

    // PeoplePicker populates its dataset dynamically from search --
    // override ComboBox's auto-disable-on-empty-dataset behavior.
    this._isDisabled = comboBoxProps.isDisabled ?? false;

    this._minimumCharacters = minimumCharacters ?? 2;
    this._searchOptions = {
      maximumSuggestions,
      principalType,
      principalSource,
    };

    this._debouncedSearch = debounce(
      (query: string) => this._executeSearch(query),
      debounceMs ?? 300
    );
  }

  // -- Search --

  private async _executeSearch(query: string): Promise<void> {
    this.instance?.addClass('form-control--loading');

    try {
      const results = await searchUsers(query, this._searchOptions);
      if (!this.isAlive) return;

      this._lastSearchResults = results;

      const options: ComboBoxOptionProps[] = results.map((r) => ({
        label: r.DisplayText,
        value: r.Key,
        disabled: !r.IsResolved,
      }));

      this._dataset = options;
      this._filteredDataset = options;
      this._refreshDropdownList();
    } finally {
      if (this.isAlive) {
        this.instance?.removeClass('form-control--loading');
      }
    }
  }

  // -- Event listeners --

  protected override _onSearchEventListeners(): void {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar input`);

    input?.on('keyup', (e) => {
      const event = e.originalEvent;

      if (!event?.key.match(/^[\w\s]$/) && event?.key !== 'Backspace' && event?.key !== 'Delete') return;

      const value = input.val()?.toString() || '';

      if (value.length >= this._minimumCharacters) {
        this._debouncedSearch(value);
      } else {
        this._debouncedSearch.cancel();
        this._dataset = [];
        this._filteredDataset = [];
        this._refreshDropdownList();
      }
    });
  }

  // -- Lifecycle --

  override remove(): void {
    this._debouncedSearch.cancel();
    super.remove();
  }

  // -- Getters --

  /** Raw PeopleSearchResult array from the last completed search. */
  get searchResults(): PeopleSearchResult[] {
    return this._lastSearchResults;
  }

  /** Full PeopleSearchResult for the currently selected option, or undefined. */
  get selectedResult(): PeopleSearchResult | undefined {
    const selected = this._dataset.find((o) => o.checked);
    if (!selected) return undefined;
    return this._lastSearchResults.find((r) => r.Key === selected.value);
  }
}
