import Fuse from 'fuse.js';
import { FormControl, FormControlProps } from '../../../abstracts/FormControl.abstract';
import { getIcon } from '../../media/Icon';
import { FormField } from '../../../../utils/form/FormField.class';

// ============================================================ TYPES

/** Accepted dataset formats: raw strings or structured option objects. */
export type ComboBoxDataset = string[] | ComboBoxOptionProps[];

/** Represents an option of a ComboBox dataset. */
export interface ComboBoxOptionProps {
  /** Text to be displayed */
  label: string;
  /** Actual option value */
  value: string;
  /** Indicates whether the option is selectable */
  disabled?: boolean;
  checked?: boolean;
}

export interface ComboBoxProps extends FormControlProps {
  /** Allows the user to select multiple options. @default false */
  allowMultiple?: boolean;
  /** Placeholder text for the input field. @default "Select..." */
  placeholder?: string;
  /** If filtering is enabled, this is used for the clear button's text. @default "Clear..." */
  clearText?: string;
  /** Indicates if dataset is filterable. @default true */
  allowFiltering?: boolean;
  /** Callback that receives the current selection each time an option is toggled. */
  onSelectHandler?: (selection: ComboBoxOptionProps | ComboBoxOptionProps[]) => void;
  /** When true the full options array is returned (with checked flags), not only checked items. @default false */
  returnFullDataset?: boolean;
  /** When true, allows the user to create new options by typing text that doesn't match existing options. @default false */
  allowCreate?: boolean;
  /**
   * When provided, this replaces the default Fuse.js filter.
   * @param search The current string input from the searchbar.
   * @returns Filtered array of options.
   */
  filteringFunction?: (search: string) => ComboBoxOptionProps[];
}

// ============================================================ CLASS

export class ComboBox extends FormControl<ComboBoxOptionProps | ComboBoxOptionProps[]> {
  protected _dataset: ComboBoxOptionProps[];
  protected _filteredDataset: ComboBoxOptionProps[];

  private _allowMultiple: boolean;
  private _placeholder: string;
  private _onSelectHandler?: (selection: ComboBoxOptionProps | ComboBoxOptionProps[]) => void;
  private _clearText: string;
  private _isDropdownOpen: boolean;
  private _allowFiltering: boolean;
  private _filterFn: (search: string) => ComboBoxOptionProps[];
  private _returnFullDataset: boolean;
  private _explicitlyDisabled: boolean;
  private _fuseInstance: Fuse<ComboBoxOptionProps> | null = null;
  private _allowCreate: boolean;
  private _focusedIndex: number = -1;
  private _pendingTimeouts: Set<ReturnType<typeof setTimeout>> = new Set();

  constructor(
    field: FormField<ComboBoxOptionProps | ComboBoxOptionProps[]>,
    dataset: ComboBoxDataset,
    props?: ComboBoxProps
  ) {
    super(field, props ?? {});

    this._explicitlyDisabled = props?.isDisabled ?? false;
    this._dataset = this._normalizeDataset(dataset);
    this._filteredDataset = this._dataset;
    this._allowMultiple = props?.allowMultiple ?? false;
    this._placeholder = props?.placeholder ?? 'Select...';
    this._onSelectHandler = props?.onSelectHandler;
    this._clearText = props?.clearText ?? 'Clear...';
    this._isDropdownOpen = false;
    this._allowFiltering = props?.allowFiltering ?? true;
    this._returnFullDataset = props?.returnFullDataset ?? false;
    this._filterFn = props?.filteringFunction ?? ((search: string) => this._defaultFilteringFunction(search));
    this._allowCreate = props?.allowCreate ?? false;
    this._disableOnEmptyDataset();
  }

  // ============================================================ NORMALIZATION

  private _normalizeDataset(data: ComboBoxDataset): ComboBoxOptionProps[] {
    if (data.length === 0) return [];
    if (typeof data[0] === 'string') {
      return (data as string[]).map((s) => ({ label: s, value: s }));
    }
    return data as ComboBoxOptionProps[];
  }

  // ============================================================ FUSE CACHE

  private _getFuseInstance(): Fuse<ComboBoxOptionProps> {
    if (!this._fuseInstance) {
      this._fuseInstance = new Fuse(this._dataset, {
        minMatchCharLength: 2,
        includeScore: true,
        keys: [
          { name: 'label', weight: 2 },
          { name: 'value', weight: 1 },
        ],
      });
    }
    return this._fuseInstance;
  }

  private _invalidateFuseCache(): void {
    this._fuseInstance = null;
  }

  // ============================================================ FILTERING

  private _defaultFilteringFunction(search: string): ComboBoxOptionProps[] {
    return this._getFuseInstance().search(search).map((e) => e.item);
  }

  // ============================================================ DISABLE LOGIC

  private _disableOnEmptyDataset(): void {
    if (this._explicitlyDisabled) return;
    if (this._allowCreate) return;
    this._isDisabled = !this._dataset || this._dataset.length === 0;
  }

  // ============================================================ TIMEOUT TRACKING

  private _trackTimeout(fn: () => void, ms: number): ReturnType<typeof setTimeout> {
    const id = setTimeout(() => {
      this._pendingTimeouts.delete(id);
      fn();
    }, ms);
    this._pendingTimeouts.add(id);
    return id;
  }

  private _clearAllTimeouts(): void {
    this._pendingTimeouts.forEach(clearTimeout);
    this._pendingTimeouts.clear();
  }

  // ============================================================ HTML BUILDERS

  private _createSearchBar(): string {
    const listboxId = `${this.id}-listbox`;
    return `<div class="${this.topClassBEM}__searchbar">
      <input
        class="${this.topClassBEM}__searchbar__input"
        placeholder="${this._placeholder}"
        spellcheck="false"
        autocomplete="off"
        role="combobox"
        aria-expanded="${this._isDropdownOpen}"
        aria-haspopup="listbox"
        aria-owns="${listboxId}"
        aria-autocomplete="list"
      />
      <span class="${this.topClassBEM}__searchbar__clear" style="display:none">
        ${getIcon('close-line')}
      </span>
      <span class="${this.topClassBEM}__searchbar__icon">
        ${getIcon(this._isDropdownOpen ? 'arrow-up-s-line' : 'arrow-down-s-line')}
      </span>
    </div>`;
  }

  private _createDropdown(): string {
    const listboxId = `${this.id}-listbox`;
    const multiAttr = this._allowMultiple ? ' aria-multiselectable="true"' : '';
    return `<div
      class="${this.topClassBEM}__dropdown"
      style="display:none"
    >
      ${this._createCreateOption()}
      <div
        class="${this.topClassBEM}__dropdown__list"
        role="listbox"
        id="${listboxId}"
        ${multiAttr}
      >
        ${this._createOptionsList()}
      </div>
      ${this._allowMultiple
        ? `<button class="${this.topClassBEM}__clear-btn">${this._clearText}</button>`
        : ''
      }
    </div>`;
  }

  private _createOption(option: ComboBoxOptionProps, index: number): string {
    const optId = `${this.id}-opt-${index}`;
    const selectedClass = option.checked ? `${this.topClassBEM}__option--selected` : '';
    const disabledClass = option.disabled ? `${this.topClassBEM}__option--disabled` : '';
    return `<div
      class="${this.topClassBEM}__option ${selectedClass} ${disabledClass}"
      id="${optId}"
      role="option"
      data-value="${option.value}"
      ${option.disabled ? 'data-disabled aria-disabled="true"' : ''}
      aria-selected="${!!option.checked}"
      tabindex="-1"
    >
      <span>${option.label}</span>
      ${getIcon('check-line')}
    </div>`;
  }

  private _createOptionsList(): string {
    return this._filteredDataset.map((opt, i) => this._createOption(opt, i)).join('');
  }

  private _createCreateOption(): string {
    if (!this._allowCreate) return '';
    return `<div class="${this.topClassBEM}__create-option" style="display:none">
      <span class="${this.topClassBEM}__create-option__icon">${getIcon('add-line')}</span>
      <span class="${this.topClassBEM}__create-option__text"></span>
    </div>`;
  }

  // ============================================================ REFRESH HELPERS

  protected _refreshDropdownList(): void {
    this.instance?.find(`.${this.topClassBEM}__dropdown__list`).html(this._createOptionsList());
    this._bindOptionClickHandlers();
    this._bindKeyboardNavigation();
    this._updateCreateOption();
  }

  private _updateCreateOption(): void {
    if (!this._allowCreate) return;
    const createEl = this.instance?.find(`.${this.topClassBEM}__create-option`);
    if (!createEl?.length) return;

    const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
    const text = input?.val()?.toString().trim() || '';

    if (!text) {
      createEl.hide();
      return;
    }

    const exactMatch = this._filteredDataset.some(
      (opt) => opt.label.toLowerCase() === text.toLowerCase()
    );

    if (exactMatch) {
      createEl.hide();
    } else {
      createEl.find(`.${this.topClassBEM}__create-option__text`).text(`Create "${text}"`);
      createEl.show();
    }
  }

  private _refreshSearchBar(): void {
    this.instance?.find(`.${this.topClassBEM}__searchbar`).replaceWith(this._createSearchBar());
    this._bindSearchBarEventHandlers();
    if (this._allowFiltering) this._onSearchEventListeners();
    if (!this._allowMultiple) this._bindClearIconHandler();
  }

  private _refreshChevron(): void {
    this.instance
      ?.find(`.${this.topClassBEM}__searchbar__icon`)
      .html(getIcon(this._isDropdownOpen ? 'arrow-up-s-line' : 'arrow-down-s-line'));
  }

  // ============================================================ DISPLAY

  private _displaySelection(): void {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
    const displayLabel = this._dataset
      .filter((opt) => opt.checked)
      .map((opt) => opt.label)
      .join(', ');

    input?.val(displayLabel);
    input?.attr('title', displayLabel || '');

    // Show/hide clear icon for single-select
    if (!this._allowMultiple) {
      const clearIcon = this.instance?.find(`.${this.topClassBEM}__searchbar__clear`);
      if (displayLabel) {
        clearIcon?.show();
      } else {
        clearIcon?.hide();
      }
    }
  }

  // ============================================================ SELECTION LOGIC

  private _selectByValue(value: string): void {
    const target = this._dataset.find((o) => o.value === value);
    if (!target || target.disabled) return;

    if (this._allowMultiple) {
      target.checked = !target.checked;
    } else {
      // Single select: if same option is already checked, deselect it; otherwise select it
      const wasChecked = target.checked;
      this._dataset.forEach((o) => { o.checked = false; });
      target.checked = !wasChecked;
    }

    this._afterSelection();
    this._onSelectHandlerProxy();
  }

  private _createNewOption(text: string): void {
    const newOption: ComboBoxOptionProps = { label: text, value: text };
    this._dataset.push(newOption);
    this._invalidateFuseCache();
    this._filteredDataset = this._dataset;
    this._selectByValue(text);
    this._closeDropdown();
  }

  private _afterSelection(): void {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
    const searchText = input?.val()?.toString() || '';

    if (searchText) {
      // Filter was active -- full reset
      this._filteredDataset = this._dataset;
      this._refreshDropdownList();
    } else {
      // No filter -- targeted class toggle only
      this._updateOptionSelectedStates();
    }
    this._displaySelection();
  }

  private _updateOptionSelectedStates(): void {
    const options = this.instance?.find(`.${this.topClassBEM}__option`);
    if (!options) return;

    options.each((_, el) => {
      const $el = $(el);
      const value = $el.attr('data-value');
      const opt = this._dataset.find((o) => o.value === value);
      if (!opt) return;

      if (opt.checked) {
        $el.addClass(`${this.topClassBEM}__option--selected`);
        $el.attr('aria-selected', 'true');
      } else {
        $el.removeClass(`${this.topClassBEM}__option--selected`);
        $el.attr('aria-selected', 'false');
      }
    });
  }

  protected _onSelectHandlerProxy(): void {
    const data = this._dataset.filter((e) => e.checked);

    if (this._allowMultiple) this._value.value = data;
    else this._value.value = data[0];

    this._onSelectHandler?.(this._returnFullDataset ? this._dataset : this._value.value);
    this._validate();
  }

  private _onResetFilteredDataSearch(): void {
    this._displaySelection();
    this._filteredDataset = this._dataset;
    this._refreshDropdownList();
  }

  // ============================================================ DROPDOWN CONTROL

  private _openDropdown(): void {
    this.instance?.addClass(`${this.topClassBEM}--topmost`);
    this.instance?.find(`.${this.topClassBEM}__dropdown`).slideDown();
    this._isDropdownOpen = true;
    this.instance?.find(`.${this.topClassBEM}__searchbar__input`).attr('aria-expanded', 'true');
    this._refreshChevron();
  }

  private _closeDropdown(): void {
    const duration = 300;
    this.instance?.find(`.${this.topClassBEM}__dropdown`).slideUp({ duration });
    this.instance?.find(`.${this.topClassBEM}__dropdown`).scrollTop(0);
    this._trackTimeout(() => this.instance?.removeClass(`${this.topClassBEM}--topmost`), duration);
    this._isDropdownOpen = false;
    this.instance?.find(`.${this.topClassBEM}__searchbar__input`).attr('aria-expanded', 'false');
    this._refreshChevron();
    this._focusedIndex = -1;
    this.instance?.find(`.${this.topClassBEM}__option--focused`).removeClass(`${this.topClassBEM}__option--focused`);
    this.instance?.find(`.${this.topClassBEM}__create-option--focused`).removeClass(`${this.topClassBEM}__create-option--focused`);
  }

  // ============================================================ KEYBOARD NAVIGATION

  private _bindKeyboardNavigation(): void {
    this.instance?.off('keydown.combobox-nav');
    this.instance?.on('keydown.combobox-nav', (e) => {
      const event = e.originalEvent;
      if (!event) return;

      switch (event.key) {
        case 'ArrowDown':
          event.preventDefault();
          if (!this._isDropdownOpen) {
            this._openDropdown();
          }
          this._moveFocus(1);
          break;
        case 'ArrowUp':
          event.preventDefault();
          this._moveFocus(-1);
          break;
        case 'Enter':
          event.preventDefault();
          this._selectFocusedOption();
          break;
        case 'Escape':
          event.preventDefault();
          this._closeDropdown();
          this._onResetFilteredDataSearch();
          break;
      }
    });
  }

  private _moveFocus(direction: number): void {
    const options = this._filteredDataset;
    const createRowVisible = this._allowCreate &&
      (this.instance?.find(`.${this.topClassBEM}__create-option`)?.css('display') !== 'none');
    const maxIndex = createRowVisible ? options.length : options.length - 1;

    if (maxIndex < 0) return;

    let next = this._focusedIndex + direction;

    // Clamp
    if (next < 0) next = 0;
    if (next > maxIndex) next = maxIndex;

    // Skip disabled options (but not the create row index)
    if (next < options.length) {
      const maxAttempts = options.length;
      let attempts = 0;
      while (attempts < maxAttempts && next < options.length && options[next]?.disabled) {
        next += direction;
        attempts++;
      }
      if (next < 0) next = 0;
      if (next > maxIndex) next = maxIndex;
      // If we landed on a disabled option and couldn't skip, bail
      if (next < options.length && options[next]?.disabled) return;
    }

    // Remove previous focus from options and create row
    this.instance?.find(`.${this.topClassBEM}__option--focused`).removeClass(`${this.topClassBEM}__option--focused`);
    this.instance?.find(`.${this.topClassBEM}__create-option--focused`).removeClass(`${this.topClassBEM}__create-option--focused`);

    this._focusedIndex = next;

    if (next === options.length && createRowVisible) {
      // Focus the create row
      const createEl = this.instance?.find(`.${this.topClassBEM}__create-option`);
      createEl?.addClass(`${this.topClassBEM}__create-option--focused`);
      this.instance?.find(`.${this.topClassBEM}__searchbar__input`).removeAttr('aria-activedescendant');
      createEl?.[0]?.scrollIntoView({ block: 'nearest' });
    } else {
      // Focus a regular option
      const optEl = this.instance?.find(`#${this.id}-opt-${next}`);
      optEl?.addClass(`${this.topClassBEM}__option--focused`);
      this.instance?.find(`.${this.topClassBEM}__searchbar__input`).attr('aria-activedescendant', `${this.id}-opt-${next}`);

      const listEl = this.instance?.find(`.${this.topClassBEM}__dropdown__list`)?.[0];
      const focusedEl = optEl?.[0];
      if (listEl && focusedEl) {
        const listRect = listEl.getBoundingClientRect();
        const optRect = focusedEl.getBoundingClientRect();
        if (optRect.bottom > listRect.bottom || optRect.top < listRect.top) {
          focusedEl.scrollIntoView({ block: 'nearest' });
        }
      }
    }
  }

  private _selectFocusedOption(): void {
    if (this._focusedIndex < 0) return;

    // Create row is at virtual index === _filteredDataset.length
    if (this._allowCreate && this._focusedIndex === this._filteredDataset.length) {
      const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
      const text = input?.val()?.toString().trim() || '';
      if (text) this._createNewOption(text);
      return;
    }

    if (this._focusedIndex >= this._filteredDataset.length) return;
    const opt = this._filteredDataset[this._focusedIndex];
    this._selectByValue(opt.value);
  }

  // ============================================================ EVENT BINDINGS

  private _bindOptionClickHandlers(): void {
    this.instance?.find(`.${this.topClassBEM}__option`).each((_, el) => {
      $(el).on('click', () => {
        if ($(el).attr('data-disabled') !== undefined) return;
        const value = $(el).attr('data-value');
        if (value !== undefined) this._selectByValue(value);
      });
    });
  }

  private _bindSearchBarEventHandlers(): void {
    this.instance?.find(`.${this.topClassBEM}__searchbar`)?.on('click', () => {
      if (!this._isDropdownOpen) this._openDropdown();
    });

    // On focus, clear input text so user can type a filter
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
    input?.on('focus', () => input.val(''));
  }

  protected _onSearchEventListeners(): void {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar input`);

    input?.on('keyup', (e) => {
      const event = e.originalEvent;
      if (!event) return;

      // Only react to printable characters, Backspace, and Delete
      if (!event.key.match(/^[\w\s]$/) && event.key !== 'Backspace' && event.key !== 'Delete') return;

      const value = input.val()?.toString() || '';

      this._filteredDataset = this._filterFn(value);

      if (this._filteredDataset.length === 0) {
        this._filteredDataset = this._dataset;
      }

      this._focusedIndex = -1;
      this._refreshDropdownList();
    });
  }

  private _bindBlurHandler(): void {
    this.instance?.on('focusout', () => {
      this._trackTimeout(() => {
        const active = document.activeElement;
        if (!this.instance?.[0]?.contains(active)) {
          this._closeDropdown();
          this._onResetFilteredDataSearch();
        }
      }, 0);
    });
  }

  private _bindClearIconHandler(): void {
    this.instance?.find(`.${this.topClassBEM}__searchbar__clear`)?.on('click', (e) => {
      e.stopPropagation();
      this.clearSelection();
    });
  }

  private _bindCreateOptionHandler(): void {
    this.instance?.find(`.${this.topClassBEM}__create-option`).on('click', () => {
      const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
      const text = input?.val()?.toString().trim() || '';
      if (text) this._createNewOption(text);
    });
  }

  private _bindClearButtonHandler(): void {
    this.instance?.find(`.${this.topClassBEM}__clear-btn`).on('click', () => {
      this.clearSelection();
      this._closeDropdown();
    });
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();
    this._bindOptionClickHandlers();
    this._bindSearchBarEventHandlers();
    this._bindBlurHandler();
    this._bindKeyboardNavigation();

    if (this._allowFiltering) this._onSearchEventListeners();
    if (this._allowCreate) this._bindCreateOptionHandler();

    if (this._allowMultiple) {
      this._bindClearButtonHandler();
    } else {
      this._bindClearIconHandler();
      // Close dropdown on single-select option click
      this.instance?.find(`.${this.topClassBEM}__dropdown__list`).on('click', () => this._closeDropdown());
    }
  }

  // ============================================================ PUBLIC API

  clearSelection(): void {
    this._dataset.forEach((e) => { e.checked = false; });
    this._onResetFilteredDataSearch();
    this._onSelectHandlerProxy();
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);
    input?.val('');
    input?.removeAttr('title');
  }

  get modifierClasses(): string {
    const mods = [super.modifierClasses];
    if (this._allowFiltering) mods.push(`${this.topClassBEM}--filterable`);
    if (this._isDropdownOpen) mods.push(`${this.topClassBEM}--open`);
    return mods.join(' ');
  }

  toString(): string {
    return `
      <div
        id="${this.id}"
        class="${this.class} ${this.modifierClasses}"
        tabindex="-1"
      >
        ${this._createSearchBar()}
        ${this._createDropdown()}
      </div>
    `;
  }

  // ============================================================ GETTERS & SETTERS

  get dataset(): ComboBoxOptionProps[] {
    return this._dataset;
  }

  set dataset(data: ComboBoxDataset) {
    this._dataset = this._normalizeDataset(data);
    this._filteredDataset = this._dataset;
    this._invalidateFuseCache();
    this._disableOnEmptyDataset();
    this.render();
  }

  set filteringFunction(callback: (search: string) => ComboBoxOptionProps[]) {
    this._filterFn = callback;
  }

  // ============================================================ LIFECYCLE

  render(): void {
    super.render(false);
    this._displaySelection();
  }

  remove(): void {
    this._clearAllTimeouts();
    super.remove();
  }
}
