import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { SPARC_PREFIX } from '../../../utils/misc/identity';
import { HTMDElement, HTMDElementProps } from '../../abstracts/HTMDElement.abstract';

export type ContainerTags =
  | 'div'
  | 'span'
  | 'header'
  | 'main'
  | 'footer'
  | 'section'
  | 'article'
  | 'nav';

export interface ContainerProps extends HTMDElementProps {
  as?: ContainerTags;
  selectableItems?: boolean;
}

export class Container extends HTMDElement {
  protected _tag: ContainerTags;
  public selectableItems: boolean;
  constructor(children: HTMDNode, props?: ContainerProps) {
    super(children, props);
    this._tag = props?.as ?? 'div';
    this.selectableItems = props?.selectableItems ?? false;
  }

  protected get _modifierClasses() {
    const mods: string[] = [];
    if (!/^container$/.test(this.name)) mods.push(`${SPARC_PREFIX}__container`);
    if (this.selectableItems) mods.push(`${this.topClassBEM}--selectable-items`);
    return mods.join(' ');
  }

  toString() {
    return `<${this._tag} 
                      id="${this.id}"
                      class="${this.class} ${this._modifierClasses}"
                          tabindex='-1'
                  />`;
  }
}
