import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { getIcon } from '../media/Icon';
import { Container, ContainerProps } from './Container';

export interface AccordionItemProps extends ContainerProps {
  isInitialOpen?: boolean;
  class?: string;
  onOpenCallback?: () => void;
  onCloseCallback?: () => void;
}

export class AccordionItem extends Container {
  private _isOpen: boolean;
  private _header: string;
  public onOpenCallback: () => void;
  public onCloseCallback: () => void;

  constructor(header: string, children: HTMDNode, props?: AccordionItemProps) {
    super(children, { class: props?.class ?? '' });
    this._isOpen = props?.isInitialOpen ?? false;
    this._header = header;
    this.onOpenCallback = props?.onOpenCallback || (() => {});
    this.onCloseCallback = props?.onCloseCallback || (() => {});
  }

  protected get _modifierClasses(): string {
    const mods = [super._modifierClasses];
    if (this._isOpen) mods.push(`${this.topClassBEM}--open`);
    return mods.join(' ');
  }

  private _createIcon() {
    return `<span class="${this.topClassBEM}__header__icon">
                  ${getIcon('arrow-down-s-line')}
                  </span>`;
  }
  private _createHeader() {
    return `<div class="${this.topClassBEM}__header">
                  <span class="${this.topClassBEM}__header__content">${this._header}</span>
                  ${this._createIcon()}
                </div>`;
  }

  private _createBody() {
    return `<div class="${this.topClassBEM}__body">
              <div class="${this.topClassBEM}__content"/>
            </div>`;
  }
  toString(): string {
    const accordion = $(super.toString());
    accordion.append(this._createHeader());
    accordion.append(this._createBody());
    return accordion[0].outerHTML;
  }

  render(): void {
    super.render(true, {
      childrenContainerSelector: `.${this.topClassBEM}__content`,
    });
  }

  protected _handleAccordionToggle() {
    if (this._isOpen) this.onCloseCallback();
    else this.onOpenCallback();
    this._isOpen = !this._isOpen;
    if (this._isOpen) this.instance?.addClass(`${this.topClassBEM}--open`);
    else this.instance?.removeClass(`${this.topClassBEM}--open`);
  }
  protected _containerToggleEventListener() {
    const header = this.instance?.find(`.${this.topClassBEM}__header`);
    header?.on('click', () => this._handleAccordionToggle());
  }

  close(): void {
    if (!this._isOpen) return;
    this._isOpen = false;
    this.instance?.removeClass(`${this.topClassBEM}--open`);
    this.onCloseCallback();
  }

  open(): void {
    if (this._isOpen) return;
    this._isOpen = true;
    this.instance?.addClass(`${this.topClassBEM}--open`);
    this.onOpenCallback();
  }
  toggle(): void {
    this._handleAccordionToggle();
  }

  get isOpen() {
    return this._isOpen;
  }
  protected _applyEventListeners(): void {
    super._applyEventListeners();
    this._containerToggleEventListener();
  }
}
