export interface RuntimeEventOptions {
  bubbles?: boolean;
  cancelable?: boolean;
}
export interface RuntimeEventListenerOptions {
  once?: boolean;
}

export abstract class RuntimeEvent extends Event {
  protected _target: EventTarget;

  constructor(eventTarget: EventTarget, options?: RuntimeEventOptions) {
    const eventType = new.target.name.toLowerCase();

    super(eventType, {
      bubbles: options?.bubbles ?? true,
      cancelable: options?.cancelable ?? true,
    });

    this._target = eventTarget;
  }

  protected static _createListener<E extends Event>(
    eventName: string,
    callback: (e?: E) => void,
    target: EventTarget,
    options: RuntimeEventListenerOptions = { once: false }
  ) {
    const wrapperFn = (e: Event) => callback(e as E);
    target.addEventListener(eventName, wrapperFn, options);
    return () => target.removeEventListener(eventName, wrapperFn);
  }
  dispatch() {
    return this._target.dispatchEvent(this);
  }

  get target() {
    return this._target;
  }
}
