import Toastify from 'toastify-js';
import { SPARC_PREFIX } from '../../../utils/misc/identity';

export interface ToastOptions {
  /**
   * Duration for which the toast should be displayed. -1 for permanent toast
   */
  duration?: number;
  autoClose?: boolean;

  /**
   * To show the toast from top or bottom
   */
  verticalAlign?: 'top' | 'bottom';
  /**
   * To show the toast on left or right
   */
  horizontalAlign?: 'left' | 'right';

  /**
   * Ability to provide custom class name for further customization
   */
  className?: string;
  /**
   * To stop timer when hovered over the toast (Only if duration is set)
   */
  stopOnFocus?: boolean;
  /**
   * Invoked when the toast is dismissed
   */
  onClose?: () => void;

  /**
   * Ability to add some offset to axis
   */
  offset?: { x?: number | string; y?: number | string };
}

export type ToastType = 'error' | 'success' | 'info' | 'warning';

export interface ToastLoadingController {
  success(message: string, options?: ToastOptions): void;
  error(message: string, options?: ToastOptions): void;
  dismiss(): void;
}

export interface ToastPromiseMessages<T> {
  loading: string;
  success: string | ((value: T) => string);
  error: string | ((reason: unknown) => string);
}

export class Toast {
  private static readonly _defaults: Record<ToastType, { duration: number; autoClose: boolean }> = {
    success: { duration: 4000, autoClose: true },
    info:    { duration: 5000, autoClose: true },
    warning: { duration: 6000, autoClose: true },
    error:   { duration: 8000,   autoClose: true },
  };

  private static _show(message: string, type: ToastType | 'loading', options: ToastOptions = {}): { hideToast(): void } {
    const defaults = type === 'loading'
      ? { duration: -1, autoClose: false }
      : Toast._defaults[type];
    const autoClose = options.autoClose ?? defaults.autoClose;

    const baseClass = `${SPARC_PREFIX}__toast`,
      className = `${baseClass} toastify--${type} ${options.className ?? ''}`;

    return Toastify({
      text: message,
      className,
      duration: autoClose ? (options.duration ?? defaults.duration) : -1,
      gravity: options.verticalAlign ?? 'top',
      position: options.horizontalAlign ?? 'right',
      stopOnFocus: options.stopOnFocus ?? true,
      close: true,
      offset: options.offset as Toastify.Offset,
      callback: options.onClose,
    }).showToast() as unknown as { hideToast(): void };
  }

  static success(message: string, options?: ToastOptions): void {
    this._show(message, 'success', options);
  }

  static error(message: string, options?: ToastOptions): void {
    this._show(message, 'error', options);
  }

  static info(message: string, options?: ToastOptions): void {
    this._show(message, 'info', options);
  }

  static warning(message: string, options?: ToastOptions): void {
    this._show(message, 'warning', options);
  }

  static loading(message: string, options?: ToastOptions): ToastLoadingController {
    const instance = Toast._show(message, 'loading', { ...options, autoClose: false });
    let resolved = false;

    const resolve = (type: 'success' | 'error', msg: string, opts?: ToastOptions) => {
      if (resolved) return;
      resolved = true;
      instance.hideToast();
      Toast._show(msg, type, opts);
    };

    return {
      success: (msg, opts?) => resolve('success', msg, opts),
      error:   (msg, opts?) => resolve('error', msg, opts),
      dismiss: () => { if (!resolved) { resolved = true; instance.hideToast(); } },
    };
  }

  static promise<T>(
    promise: Promise<T>,
    messages: ToastPromiseMessages<T>,
    options?: ToastOptions,
  ): Promise<T> {
    const toast = Toast.loading(messages.loading, options);
    return promise.then(
      (value) => {
        const msg = typeof messages.success === 'function' ? messages.success(value) : messages.success;
        toast.success(msg);
        return value;
      },
      (reason: unknown) => {
        const msg = typeof messages.error === 'function' ? messages.error(reason) : messages.error;
        toast.error(msg);
        throw reason;
      },
    );
  }
}
