import { SystemError } from '../../error-handling/errors/SystemError';
import { refreshRequestDigest } from './requestDigest';

/**
 * Options for SharePoint REST API request functions.
 *
 * Extends jQuery's `JQueryAjaxSettings` with an optional `requestDigest` field
 * for write operations (POST, DELETE, MERGE). When omitted on write requests,
 * `_spPageContextInfo.formDigestValue` is used automatically.
 *
 * @see {@link https://api.jquery.com/jQuery.ajax/} for the full JQueryAjaxSettings spec.
 */
export interface SPRequestOptions extends JQueryAjaxSettings {
  /**
   * SharePoint request digest token for write operations.
   *
   * When provided, this value is injected as the `X-RequestDigest` header
   * on POST, DELETE, and MERGE requests. When omitted, the current site's
   * `_spPageContextInfo.formDigestValue` is used as the default.
   *
   * Typically obtained from {@link SiteApi.requestDigest}.
   */
  requestDigest?: string;
}

/** Default Accept header for SharePoint REST API responses without OData metadata. */
const SP_ACCEPT = 'application/json;odata=nometadata';

/** Content-Type header for SharePoint REST API write payloads with verbose OData. */
const SP_CONTENT_TYPE = 'application/json;odata=verbose';

/** Wildcard ETag match header -- disables concurrency checks, always overwrites. */
const SP_IF_MATCH_ANY = '*';

// -- baseRequest helpers --

/**
 * Wraps `$.ajax` in a native Promise. Rejects with the raw `jqXHR` object
 * (not a {@link SystemError}) so callers can inspect `status` and `responseText`
 * for retry decisions.
 *
 * @typeParam T - The expected shape of the resolved response data.
 * @param payload - jQuery AJAX settings forwarded directly to `$.ajax()`.
 * @returns A Promise resolving with the response data or rejecting with `jqXHR`.
 */
function _ajaxToPromise<T>(payload: JQueryAjaxSettings): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    $.ajax(payload)
      .done((res) => resolve(res as T))
      .fail((jqXHR: JQueryXHR) => reject(jqXHR));
  });
}

/**
 * Detects SharePoint's expired form digest 403 response. Returns `true` when
 * `status` is 403 AND `responseText` contains "security validation" (case-insensitive).
 * This distinguishes digest expiry from genuine permission-denied 403s.
 *
 * @param jqXHR - The jQuery XHR object from a failed request.
 * @returns `true` if the failure indicates an expired digest token.
 */
function _isDigestExpiredError(jqXHR: JQueryXHR): boolean {
  return jqXHR.status === 403 && /security validation/i.test(jqXHR.responseText ?? '');
}

/**
 * Converts a raw `jqXHR` rejection into a {@link SystemError}. Single point of
 * error formatting -- extracts `status` and `responseText`/`statusText` into
 * a consistent `"HTTP <status> -- <detail>"` message.
 *
 * @param method - The HTTP method name used in the `SystemError` name
 *   (e.g., `"GET"` produces `"APIException: GET"`).
 * @param jqXHR - The jQuery XHR object from a failed request.
 * @returns A `SystemError` ready to be thrown.
 */
function _toSystemError(method: string, jqXHR: JQueryXHR): SystemError {
  if (jqXHR instanceof Error) {
    return new SystemError(`APIException: ${method}`, jqXHR.message);
  }
  const status = jqXHR.status ?? 0;
  const detail = jqXHR.responseText ?? jqXHR.statusText ?? 'Unknown error';
  return new SystemError(`APIException: ${method}`, `HTTP ${status} -- ${detail}`);
}

// -- baseRequest --

/**
 * Low-level AJAX dispatcher that wraps jQuery's `$.ajax()` with typed error handling.
 *
 * @internal Not part of the public API. All SharePoint request functions
 * (`spGET`, `spPOST`, `spDELETE`, `spMERGE`) delegate to this function
 * after assembling their specific headers and payloads.
 *
 * Supports two calling modes via overloads:
 *
 * - **Synchronous** (`async: false`) -- returns the response value `T` directly.
 *   Synchronous requests block the main thread and are used internally by `ListApi`
 *   for CAML queries that must resolve before subsequent logic executes.
 *
 * - **Asynchronous** (default) -- returns a `Promise<T>` that resolves with the
 *   response or rejects with a {@link SystemError}.
 *
 * When an async request fails with HTTP 403 and a "security validation" message
 * (indicating an expired form digest token), the function automatically refreshes
 * the digest via `/_api/contextinfo` and retries the request once with the new token.
 *
 * @typeParam T - The expected shape of the response data.
 *
 * @param ajaxPayload - A full jQuery AJAX settings object. The `type` field is
 *   read for error messages. All other fields are passed through to `$.ajax()`.
 *
 * @returns The response data typed as `T` (sync) or `Promise<T>` (async).
 *
 * @throws {SystemError} With name `"APIException: <METHOD>"` when the request fails.
 *   In async mode, the error message includes the HTTP status code and response text
 *   (e.g., `"HTTP 403 -- Access denied"`). In sync mode, the native error message
 *   is forwarded.
 */
function baseRequest<T>(ajaxPayload: JQueryAjaxSettings & { async: false }): T;
function baseRequest<T>(ajaxPayload: JQueryAjaxSettings): Promise<T>;
function baseRequest<T>(ajaxPayload: JQueryAjaxSettings): T | Promise<T> {
  const method = ajaxPayload.type ?? 'UNKNOWN';

  if (ajaxPayload.async === false) {
    let response: unknown;
    let syncError: JQueryXHR | undefined;

    $.ajax(ajaxPayload)
      .done((res) => (response = res))
      .fail((jqXHR: JQueryXHR) => (syncError = jqXHR));

    if (syncError) throw _toSystemError(method, syncError);
    return response as T;
  }

  return _ajaxToPromise<T>(ajaxPayload).catch((jqXHR: JQueryXHR) => {
    if (_isDigestExpiredError(jqXHR) && ajaxPayload.headers?.['X-RequestDigest']) {
      const siteUrl = ajaxPayload.url?.split('/_api/')[0];
      return refreshRequestDigest(siteUrl).then((freshToken) => {
        const retryPayload = {
          ...ajaxPayload,
          headers: { ...ajaxPayload.headers, 'X-RequestDigest': freshToken },
        };
        return _ajaxToPromise<T>(retryPayload).catch((retryJqXHR: JQueryXHR) => {
          throw _toSystemError(method, retryJqXHR);
        });
      });
    }
    throw _toSystemError(method, jqXHR);
  });
}

// -- spGET --

/**
 * Sends a GET request to a SharePoint REST API endpoint.
 *
 * Sets the following default headers (overridable via `options.headers`):
 * - `accept: application/json;odata=nometadata`
 *
 * Sets the following default AJAX settings (overridable via `options`):
 * - `async: true`
 * - `dataType: "json"`
 *
 * @typeParam T - The expected shape of the response data.
 *
 * @param url - The full REST API endpoint URL
 *   (e.g., `"/_api/web/lists/getbytitle('Tasks')/items"`).
 * @param options - Optional {@link SPRequestOptions}. Pass `{ async: false }` for
 *   synchronous execution.
 *
 * @returns `Promise<T>` in async mode, or `T` directly when `options.async` is `false`.
 *
 * @throws {SystemError} Propagated from {@link baseRequest} on request failure.
 *
 * @example
 * ```ts
 * // Async usage
 * const data = await spGET<Item[]>(
 *   "/_api/web/lists/getbytitle('Tasks')/items"
 * );
 *
 * // Sync usage (blocks main thread)
 * const data = spGET<Item[]>(
 *   "/_api/web/lists/getbytitle('Tasks')/items",
 *   { async: false }
 * );
 * ```
 */
export function spGET<T>(url: string, options: SPRequestOptions & { async: false }): T;
export function spGET<T>(url: string, options?: SPRequestOptions): Promise<T>;
export function spGET<T>(url: string, options: SPRequestOptions = {}): T | Promise<T> {
  const { headers, ...requestOptions } = options;
  const requestHeaders = $.extend(
    {
      accept: SP_ACCEPT,
    },
    headers ?? {}
  );

  const ajaxPayload = $.extend(
    {
      url,
      async: true,
      type: 'GET',
      dataType: 'json',
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest<T>(ajaxPayload);
}

// -- spPOST --

/**
 * Sends a POST request to a SharePoint REST API endpoint for creating items.
 *
 * The `options.data` object is automatically serialized via `JSON.stringify()`.
 * The `X-RequestDigest` header is auto-injected from
 * `_spPageContextInfo.formDigestValue` when no explicit `requestDigest` is provided.
 *
 * Sets the following default headers (overridable via `options.headers`):
 * - `accept: application/json;odata=nometadata`
 * - `X-HTTP-Method: POST`
 * - `Content-Type: application/json;odata=verbose`
 *
 * Sets the following default AJAX settings (overridable via `options`):
 * - `async: true`
 * - `dataType: "json"`
 *
 * @typeParam T - The expected shape of the response data.
 *
 * @param url - The full REST API endpoint URL
 *   (e.g., `"/_api/web/lists/getbytitle('Tasks')/items"`).
 * @param options - Optional {@link SPRequestOptions}. The `data` field should contain
 *   the item payload (including `__metadata`). Pass `{ async: false }` for
 *   synchronous execution.
 *
 * @returns `Promise<T>` in async mode, or `T` directly when `options.async` is `false`.
 *
 * @throws {SystemError} Propagated from {@link baseRequest} on request failure.
 *
 * @example
 * ```ts
 * const result = await spPOST("/_api/web/lists/getbytitle('Tasks')/items", {
 *   data: {
 *     __metadata: { type: "SP.Data.TasksListItem" },
 *     Title: "New Task",
 *   },
 * });
 * ```
 */
export function spPOST<T>(url: string, options: SPRequestOptions & { async: false }): T;
export function spPOST<T>(url: string, options?: SPRequestOptions): Promise<T>;
export function spPOST<T>(url: string, options: SPRequestOptions = {}): T | Promise<T> {
  const { headers, data, ...requestOptions } = options;
  /* eslint-disable @typescript-eslint/naming-convention */
  const requestHeaders = $.extend(
    {
      accept: SP_ACCEPT,
      'X-HTTP-Method': 'POST',
      'Content-Type': SP_CONTENT_TYPE,
    },
    headers ?? {}
  );

  requestHeaders['X-RequestDigest'] = options.requestDigest ?? _spPageContextInfo.formDigestValue;

  const ajaxPayload = $.extend(
    {
      url,
      async: true,
      type: 'POST',
      data: JSON.stringify(data),
      dataType: 'json',
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest<T>(ajaxPayload);
}

// -- spDELETE --

/**
 * Sends a DELETE request to a SharePoint REST API endpoint.
 *
 * The actual HTTP method sent is `POST` with the `X-HTTP-Method: DELETE` header
 * override, as required by SharePoint's REST API. The `X-RequestDigest` header
 * is auto-injected from `_spPageContextInfo.formDigestValue` when no explicit
 * `requestDigest` is provided.
 *
 * Sets the following default headers (overridable via `options.headers`):
 * - `accept: application/json;odata=nometadata`
 * - `X-HTTP-Method: DELETE`
 * - `Content-Type: application/json;odata=verbose`
 * - `IF-MATCH: *` (disables ETag concurrency checks, always overwrites)
 *
 * Sets the following default AJAX settings (overridable via `options`):
 * - `async: true`
 *
 * Note: Unlike GET and POST, this function does NOT set a default `dataType`,
 * since DELETE responses from SharePoint typically return no body.
 *
 * @typeParam T - The expected shape of the response data (often `void` or unused).
 *
 * @param url - The full REST API endpoint URL, including the item ID
 *   (e.g., `"/_api/web/lists/getbytitle('Tasks')/items(42)"`).
 * @param options - Optional {@link SPRequestOptions}. Pass `{ async: false }` for
 *   synchronous execution.
 *
 * @returns `Promise<T>` in async mode, or `T` directly when `options.async` is `false`.
 *
 * @throws {SystemError} Propagated from {@link baseRequest} on request failure.
 *
 * @example
 * ```ts
 * // Delete item with ID 42
 * await spDELETE("/_api/web/lists/getbytitle('Tasks')/items(42)");
 * ```
 */
export function spDELETE<T>(url: string, options: SPRequestOptions & { async: false }): T;
export function spDELETE<T>(url: string, options?: SPRequestOptions): Promise<T>;
export function spDELETE<T>(url: string, options: SPRequestOptions = {}): T | Promise<T> {
  const { headers, ...requestOptions } = options;
  /* eslint-disable @typescript-eslint/naming-convention */
  const requestHeaders = $.extend(
    {
      accept: SP_ACCEPT,
      'X-HTTP-Method': 'DELETE',
      'Content-Type': SP_CONTENT_TYPE,
      'IF-MATCH': SP_IF_MATCH_ANY,
    },
    headers ?? {}
  );

  requestHeaders['X-RequestDigest'] = options.requestDigest ?? _spPageContextInfo.formDigestValue;

  const ajaxPayload = $.extend(
    {
      url,
      async: true,
      type: 'POST',
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest<T>(ajaxPayload);
}

// -- spMERGE --

/**
 * Sends a MERGE request to a SharePoint REST API endpoint for partial updates.
 *
 * Only the fields included in `options.data` are modified; other fields remain
 * unchanged. The `options.data` object is automatically serialized via
 * `JSON.stringify()`. The actual HTTP method sent is `POST` with the
 * `X-HTTP-Method: MERGE` header override, as required by SharePoint's REST API.
 * The `X-RequestDigest` header is auto-injected from
 * `_spPageContextInfo.formDigestValue` when no explicit `requestDigest` is provided.
 *
 * Sets the following default headers (overridable via `options.headers`):
 * - `accept: application/json;odata=nometadata`
 * - `X-HTTP-Method: MERGE`
 * - `Content-Type: application/json;odata=verbose`
 * - `IF-MATCH: *` (disables ETag concurrency checks, always overwrites)
 *
 * Sets the following default AJAX settings (overridable via `options`):
 * - `async: true`
 *
 * Note: Unlike GET and POST, this function does NOT set a default `dataType`,
 * since MERGE responses from SharePoint typically return no body (HTTP 204).
 *
 * @typeParam T - The expected shape of the response data (often `void` or unused).
 *
 * @param url - The full REST API endpoint URL, including the item ID
 *   (e.g., `"/_api/web/lists/getbytitle('Tasks')/items(42)"`).
 * @param options - Optional {@link SPRequestOptions}. The `data` field should contain
 *   the partial item payload (including `__metadata`). Pass `{ async: false }` for
 *   synchronous execution.
 *
 * @returns `Promise<T>` in async mode, or `T` directly when `options.async` is `false`.
 *
 * @throws {SystemError} Propagated from {@link baseRequest} on request failure.
 *
 * @example
 * ```ts
 * // Update the Title of item 42
 * await spMERGE("/_api/web/lists/getbytitle('Tasks')/items(42)", {
 *   data: {
 *     __metadata: { type: "SP.Data.TasksListItem" },
 *     Title: "Updated Title",
 *   },
 * });
 * ```
 */
export function spMERGE<T>(url: string, options: SPRequestOptions & { async: false }): T;
export function spMERGE<T>(url: string, options?: SPRequestOptions): Promise<T>;
export function spMERGE<T>(url: string, options: SPRequestOptions = {}): T | Promise<T> {
  const { headers, data, ...requestOptions } = options;
  /* eslint-disable @typescript-eslint/naming-convention */
  const requestHeaders = $.extend(
    {
      accept: SP_ACCEPT,
      'X-HTTP-Method': 'MERGE',
      'Content-Type': SP_CONTENT_TYPE,
      'IF-MATCH': SP_IF_MATCH_ANY,
    },
    headers ?? {}
  );

  requestHeaders['X-RequestDigest'] = options.requestDigest ?? _spPageContextInfo.formDigestValue;

  const ajaxPayload = $.extend(
    {
      url,
      async: true,
      type: 'POST',
      data: JSON.stringify(data),
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest<T>(ajaxPayload);
}
