import { SystemError } from '../../error-handling/errors/SystemError';
import { CAMLQueryResponse, SPCollectionResponse } from '../../types/sharepoint/api.types';
import type { CAMLCondition, CAMLQueryObject } from '../../types/sharepoint/caml.types';
import type { SPField } from '../../types/sharepoint/site.types';
import { CurrentUser } from '../user/CurrentUser';
import { spDELETE, spGET, spMERGE, spPOST } from './httpRequests';
import { SiteApi } from './SiteApi.class';

export type { CAMLQueryObject } from '../../types/sharepoint/caml.types';

export interface CreateFieldOptions {
  title: string;
  /** When true, creates a Note (multiline text) field. Defaults to single-line Text. */
  multiline?: boolean;
  indexed?: boolean;
}

const CAML_PAGE_SIZE = 500;

/**
 * Maximum allowed nesting depth for `$or` in CAMLQueryObject.
 * Depth 0 = top-level query, depth 1 = inside $or, depth 2 = $or inside $or.
 */
const MAX_NESTING_DEPTH = 2;

export interface ListApiOptions {
  listItemType?: string;
  siteApi?: SiteApi;
}

export interface GetItemsOptions {
  /** Maximum total items to return across all pages. Default: 1000. */
  limit?: number;
}

export class ListApi {
  #title: string;
  #listItemType: string;
  protected _siteApi: SiteApi;

  constructor(title: string, options: ListApiOptions = {}) {
    this._siteApi = options?.siteApi ?? new SiteApi();
    this.#title = title;
    this.#listItemType =
      options.listItemType ??
      `SP.Data.${title.charAt(0).toUpperCase()}${title.substring(1)}ListItem`;
  }

  //============================================================
  private _buildAndClause(clauses: string[]): string {
    let result = clauses[0];
    for (let i = 1; i < clauses.length; i++) {
      result = `<And>${result}${clauses[i]}</And>`;
    }
    return result;
  }

  private _buildOrClause(clauses: string[]): string {
    let result = clauses[0];
    for (let i = 1; i < clauses.length; i++) {
      result = `<Or>${result}${clauses[i]}</Or>`;
    }
    return result;
  }

  private _parseCondition(fieldName: string, condition: CAMLCondition): string {
    if (typeof condition === 'string') {
      return `<Eq><FieldRef Name="${fieldName}" /><Value Type="Text">${condition}</Value></Eq>`;
    }

    const { operator } = condition;

    if (operator === 'IsNull' || operator === 'IsNotNull') {
      return `<${operator}><FieldRef Name="${fieldName}" /></${operator}>`;
    }

    if (operator === 'Or') {
      const matchOp = condition.match ?? 'Eq';
      const perValue = condition.value.map(
        (v) => `<${matchOp}><FieldRef Name="${fieldName}" /><Value Type="Text">${v}</Value></${matchOp}>`
      );
      return perValue.length === 1 ? perValue[0] : this._buildOrClause(perValue);
    }

    return `<${operator}><FieldRef Name="${fieldName}" /><Value Type="Text">${condition.value}</Value></${operator}>`;
  }

  private _buildWhereContent(args: CAMLQueryObject, depth: number): string | null {
    if (depth > MAX_NESTING_DEPTH) {
      throw new SystemError(
        'CAMLQuery',
        `$or nesting depth exceeds maximum of ${MAX_NESTING_DEPTH}`,
        { breaksFlow: true }
      );
    }

    const { $or, ...fieldEntries } = args;

    // Build field-level conditions (AND-ed together)
    const fieldClauses: string[] = [];
    for (const [fieldName, condition] of Object.entries(fieldEntries)) {
      fieldClauses.push(this._parseCondition(fieldName, condition as CAMLCondition));
    }
    const fieldClause =
      fieldClauses.length === 0 ? null : fieldClauses.length === 1 ? fieldClauses[0] : this._buildAndClause(fieldClauses);

    // Build cross-field $or clause
    let orClause: string | null = null;
    if ($or && $or.length > 0) {
      const orParts = $or
        .map((sub) => this._buildWhereContent(sub, depth + 1))
        .filter((part): part is string => part !== null);
      if (orParts.length > 0) {
        orClause = orParts.length === 1 ? orParts[0] : this._buildOrClause(orParts);
      }
    }

    if (fieldClause && orClause) return `<And>${fieldClause}${orClause}</And>`;
    return fieldClause ?? orClause;
  }

  protected _parseCAMLQueryObject(args: CAMLQueryObject): string {
    const rowLimit = `<RowLimit Paged="TRUE">${CAML_PAGE_SIZE}</RowLimit>`;
    const whereContent = this._buildWhereContent(args, 0);

    if (!whereContent) {
      return `<View><Query></Query>${rowLimit}</View>`;
    }

    return `<View><Query><Where>${whereContent}</Where></Query>${rowLimit}</View>`;
  }

  protected _createCAMLQueryPayload(camlQuery: string, pagingInfo?: string | null) {
    const query: Record<string, unknown> = {
      // eslint-disable-next-line @typescript-eslint/naming-convention
      __metadata: { type: 'SP.CamlQuery' },
      // eslint-disable-next-line @typescript-eslint/naming-convention
      ViewXml: camlQuery,
    };
    if (pagingInfo) {
      // eslint-disable-next-line @typescript-eslint/naming-convention
      query.ListItemCollectionPosition = { PagingInfo: pagingInfo };
    }
    return { query };
  }

  protected async _queryRequest<T>(args: CAMLQueryObject | string, limit = 1000): Promise<T[]> {
    const camlQuery = typeof args === 'string' ? args : this._parseCAMLQueryObject(args);
    const digest = await this._siteApi.getRequestDigest();
    const url = `${this.endpoint}/getitems`;
    const allItems: T[] = [];
    let pagingInfo: string | null = null;

    do {
      const payload = this._createCAMLQueryPayload(camlQuery, pagingInfo);
      const response = await spPOST<CAMLQueryResponse<T>>(url, {
        requestDigest: digest,
        data: payload,
      });

      const page = response?.value ?? [];
      allItems.push(...page);
      pagingInfo = response?.ListItemCollectionPosition?.PagingInfo ?? null;
    } while (pagingInfo && allItems.length < limit);

    return allItems.slice(0, limit);
  }
  //============================================================

  async getItems<T>(query: CAMLQueryObject | string = {}, options: GetItemsOptions = {}): Promise<T[]> {
    const { limit = 1000 } = options;
    return this._queryRequest<T>(query, limit);
  }
  async getItemByTitle<T>(title: string): Promise<T[]> {
    // eslint-disable-next-line @typescript-eslint/naming-convention
    return this._queryRequest<T>({ Title: title });
  }
  async getItemByUUID<T>(uuid: string): Promise<T[]> {
    // eslint-disable-next-line @typescript-eslint/naming-convention
    return this._queryRequest<T>({ UUID: uuid });
  }
  async getOwnedItems<T>(userId?: string): Promise<T[]> {
    const resolvedId = userId ?? String(new CurrentUser().get('siteUserId'));
    // eslint-disable-next-line @typescript-eslint/naming-convention
    return this._queryRequest<T>({ AuthorId: resolvedId });
  }
  //============================================================
  async createItem(item: Record<string, string>) {
    const itemWithMetadata = $.extend(
      {
        // eslint-disable-next-line @typescript-eslint/naming-convention
        __metadata: { type: this.#listItemType },
      },
      item
    );
    const digest = await this._siteApi.getRequestDigest();
    const endpoint = `${this.endpoint}/items`;
    return spPOST(endpoint, {
      data: itemWithMetadata,
      requestDigest: digest,
    });
  }
  async deleteItem(id: number) {
    const digest = await this._siteApi.getRequestDigest();
    const endpoint = `${this.endpoint}/items(${id})`;
    return spDELETE(endpoint, {
      requestDigest: digest,
    });
  }
  async deleteALLItems() {
    const items = await this.getItems<{ Id: number }>({}, { limit: Infinity });
    for (const item of items) {
      await this.deleteItem(item.Id);
    }
  }

  async updateItem(id: number, fields: Record<string, string>) {
    const digest = await this._siteApi.getRequestDigest();
    const data = {
      // eslint-disable-next-line @typescript-eslint/naming-convention
      __metadata: { type: this.#listItemType },
      ...fields,
    };
    return spMERGE(`${this.endpoint}/items(${id})`, {
      data,
      requestDigest: digest,
    });
  }
  //============================================================

  async getFields(): Promise<SPField[]> {
    const url = `${this.endpoint}/fields?$filter=Hidden eq false and ReadOnlyField eq false`;
    const response = await spGET<SPCollectionResponse<SPField>>(url);
    return response?.value ?? [];
  }

  async createField(options: CreateFieldOptions): Promise<SPField> {
    const digest = await this._siteApi.getRequestDigest();
    const isNote = options.multiline === true;

    /* eslint-disable @typescript-eslint/naming-convention */
    const body: Record<string, unknown> = {
      __metadata: { type: isNote ? 'SP.FieldMultiLineText' : 'SP.FieldText' },
      Title: options.title,
      FieldTypeKind: isNote ? 3 : 2,
      ...(isNote && { RichText: false }),
    };
    if (options.indexed !== undefined) body.Indexed = options.indexed;
    /* eslint-enable @typescript-eslint/naming-convention */

    return spPOST<SPField>(`${this.endpoint}/fields`, {
      requestDigest: digest,
      data: body,
    });
  }

  async deleteField(internalName: string): Promise<void> {
    const digest = await this._siteApi.getRequestDigest();
    await spDELETE(`${this.endpoint}/fields/getbyinternalnameortitle('${internalName}')`, {
      requestDigest: digest,
    });
  }

  async setFieldIndexed(internalName: string, indexed: boolean): Promise<void> {
    const digest = await this._siteApi.getRequestDigest();
    await spMERGE(`${this.endpoint}/fields/getbyinternalnameortitle('${internalName}')`, {
      data: {
        // eslint-disable-next-line @typescript-eslint/naming-convention
        __metadata: { type: 'SP.Field' },
        // eslint-disable-next-line @typescript-eslint/naming-convention
        Indexed: indexed,
      },
      requestDigest: digest,
    });
  }

  //   ===
  get endpoint() {
    return `${this._siteApi.url}/_api/web/lists/getbytitle('${this.#title}')`;
  }
  get listItemType() {
    return this.#listItemType;
  }
}
